1	/**
2	 * MessagePort protocol for UI-thread <-> AudioWorklet communication.
3	 * All messages are typed discriminated unions for type safety.
4	 */
5	
6	/** Messages sent from UI thread to AudioWorklet */
7	export type EngineCommand =
8	  | {
9	      type: "init";
10	      sampleRate: number;
11	      sharedBuffers: {
12	        metering: SharedArrayBuffer;
13	        transport: SharedArrayBuffer;
14	      };
15	    }
16	  | { type: "play" }
17	  | { type: "pause" }
18	  | { type: "stop" }
19	  | { type: "seek"; positionSeconds: number }
20	  | { type: "set-bpm"; bpm: number };
21	
22	/** Messages sent from AudioWorklet to UI thread */
23	export type EngineEvent =
24	  | { type: "ready" }
25	  | { type: "error"; message: string }
26	  | { type: "state-change"; state: "playing" | "paused" | "stopped" };
27	
28	export type MessagePortProtocol = {
29	  command: EngineCommand;
30	  event: EngineEvent;
31	};
32	
33	/**
34	 * Type-safe message sender for the engine command channel.
35	 */
36	export function postEngineCommand(
37	  port: MessagePort,
38	  command: EngineCommand,
39	): void {
40	  port.postMessage(command);
41	}
42	
43	/**
44	 * Type-safe message sender for engine events.
45	 */
46	export function postEngineEvent(port: MessagePort, event: EngineEvent): void {
47	  port.postMessage(event);
48	}
