1	/**
2	 * Look-ahead scheduler using the Chris Wilson pattern:
3	 * setInterval fires every ~25ms, scheduling audio events
4	 * that fall within the next 100ms of AudioContext time.
5	 *
6	 * This runs on the main thread. The setInterval callback is lightweight
7	 * (just math + scheduling calls), so it doesn't block rendering.
8	 */
9	
10	import type { TransportClock } from "./transport-clock";
11	
12	export type SchedulerConfig = {
13	  intervalMs: number;
14	  lookAheadMs: number;
15	};
16	
17	export type LookAheadScheduler = {
18	  start(): void;
19	  stop(): void;
20	  /** Re-sync beat phase to the current clock position (e.g. after seek). */
21	  sync(): void;
22	  readonly isRunning: boolean;
23	};
24	
25	const DEFAULT_CONFIG: SchedulerConfig = {
26	  intervalMs: 25,
27	  lookAheadMs: 100,
28	};
29	
30	export function createLookAheadScheduler(
31	  ctx: AudioContext,
32	  clock: TransportClock,
33	  config?: Partial<SchedulerConfig>,
34	  onTick?: (beatTime: number, beatNumber: number) => void,
35	): LookAheadScheduler {
36	  const intervalMs = config?.intervalMs ?? DEFAULT_CONFIG.intervalMs;
37	  const lookAheadSec =
38	    (config?.lookAheadMs ?? DEFAULT_CONFIG.lookAheadMs) / 1000;
39	
40	  let timerId: ReturnType<typeof setInterval> | null = null;
41	  let nextBeatTime = 0;
42	  let currentBeat = 0;
43	
44	  function syncToPosition(cursorSec: number): void {
45	    const spb = clock.getTempoMap().secondsPerBeat();
46	    const totalBeats = cursorSec / spb;
47	    const wholeBeat = Math.floor(totalBeats + 1e-9);
48	    const remainder = totalBeats - wholeBeat;
49	
50	    if (remainder < 1e-6) {
51	      // On a beat boundary — schedule this beat now
52	      currentBeat = wholeBeat;
53	      nextBeatTime = ctx.currentTime;
54	    } else {
55	      // Between beats — schedule next beat
56	      currentBeat = wholeBeat + 1;
57	      nextBeatTime = ctx.currentTime + (currentBeat * spb - cursorSec);
58	    }
59	  }
60	
61	  function advance(): void {
62	    if (clock.state !== "playing") return;
63	
64	    // Drive SAB cursor updates and detect loop wraps
65	    clock.updateCursor();
66	
67	    if (clock.didLoopWrap()) {
68	      syncToPosition(clock.getCursorSeconds());
69	    }
70	
71	    const scheduleUntil = ctx.currentTime + lookAheadSec;
72	    const spb = clock.getTempoMap().secondsPerBeat();
73	
74	    // Constrain scheduling window to the loop end boundary
75	    const loop = clock.getLoop();
76	    let effectiveUntil = scheduleUntil;
77	    if (loop.enabled && loop.end > loop.start) {
78	      const cursorNow = clock.getCursorSeconds();
79	      const timeToLoopEnd = loop.end - cursorNow;
80	      if (timeToLoopEnd > 0) {
81	        effectiveUntil = Math.min(
82	          scheduleUntil,
83	          ctx.currentTime + timeToLoopEnd,
84	        );
85	      }
86	    }
87	
88	    while (nextBeatTime < effectiveUntil) {
89	      onTick?.(nextBeatTime, currentBeat);
90	      currentBeat++;
91	      nextBeatTime += spb;
92	    }
93	  }
94	
95	  const scheduler: LookAheadScheduler = {
96	    get isRunning(): boolean {
97	      return timerId !== null;
98	    },
99	
100	    start(): void {
101	      if (timerId !== null) return;
102	
103	      // Phase-correct: sync beat position to current cursor
104	      syncToPosition(clock.getCursorSeconds());
105	
106	      timerId = setInterval(advance, intervalMs);
107	      advance();
108	    },
109	
110	    stop(): void {
111	      if (timerId !== null) {
112	        clearInterval(timerId);
113	        timerId = null;
114	      }
115	      nextBeatTime = 0;
116	      currentBeat = 0;
117	    },
118	
119	    sync(): void {
120	      syncToPosition(clock.getCursorSeconds());
121	    },
122	  };
123	
124	  return scheduler;
125	}
