1	/**
2	 * Insert chain manager for mixer channel strips.
3	 * Manages a serial chain of effect nodes between source and destination.
4	 * Re-wires the Web Audio graph when inserts are added/removed.
5	 */
6	
7	export type InsertEntry = {
8	  readonly id: string;
9	  readonly input: AudioNode;
10	  readonly output: AudioNode;
11	};
12	
13	export type InsertChain = {
14	  addInsert(id: string, input: AudioNode, output: AudioNode): void;
15	  removeInsert(id: string): void;
16	  getInserts(): readonly InsertEntry[];
17	  dispose(): void;
18	};
19	
20	export function createInsertChain(
21	  source: AudioNode,
22	  dest: AudioNode,
23	): InsertChain {
24	  const inserts: InsertEntry[] = [];
25	
26	  // Track the node source currently connects to, so we can disconnect
27	  // only our connection instead of severing all outgoing connections.
28	  let sourceTarget: AudioNode = dest;
29	
30	  function rewire(): void {
31	    // Disconnect only the chain's own connections
32	    try {
33	      source.disconnect(sourceTarget);
34	    } catch {
35	      // Target already disconnected — safe to ignore
36	    }
37	    for (const entry of inserts) {
38	      entry.output.disconnect();
39	    }
40	
41	    if (inserts.length === 0) {
42	      source.connect(dest);
43	      sourceTarget = dest;
44	      return;
45	    }
46	
47	    // source -> first insert input
48	    const first = inserts[0]!;
49	    source.connect(first.input);
50	    sourceTarget = first.input;
51	
52	    // Chain inserts: each output -> next input
53	    for (let i = 0; i < inserts.length - 1; i++) {
54	      const current = inserts[i]!;
55	      const next = inserts[i + 1]!;
56	      current.output.connect(next.input);
57	    }
58	
59	    // Last insert output -> dest
60	    const last = inserts[inserts.length - 1]!;
61	    last.output.connect(dest);
62	  }
63	
64	  // Initial wiring: source -> dest
65	  source.connect(dest);
66	
67	  return {
68	    addInsert(id: string, input: AudioNode, output: AudioNode): void {
69	      inserts.push({ id, input, output });
70	      rewire();
71	    },
72	
73	    removeInsert(id: string): void {
74	      const idx = inserts.findIndex((e) => e.id === id);
75	      if (idx === -1) return;
76	      const removed = inserts[idx]!;
77	      removed.output.disconnect();
78	      inserts.splice(idx, 1);
79	      rewire();
80	    },
81	
82	    getInserts(): readonly InsertEntry[] {
83	      return [...inserts];
84	    },
85	
86	    dispose(): void {
87	      try {
88	        source.disconnect(sourceTarget);
89	      } catch {
90	        // Already disconnected
91	      }
92	      for (const entry of inserts) {
93	        entry.output.disconnect();
94	      }
95	      inserts.length = 0;
96	    },
97	  };
98	}
