57	export function createCompressorFactory(): EffectFactory {
58	  return {
59	    definition: { id: "compressor", name: "Compressor", parameters: PARAMS },
60	    create(ctx, id) {
61	      let comp: DynamicsCompressorNode;
62	
63	      const effect = createBaseEffect({
64	        ctx,
65	        id,
66	        typeId: "compressor",
67	        params: PARAMS,
68	        buildChain(inputNode, outputNode) {
69	          comp = ctx.createDynamicsCompressor();
70	          inputNode.connect(comp);
71	          comp.connect(outputNode);
72	        },
73	        disposeChain() {
74	          comp.disconnect();
75	        },
76	        applyParam(key, value) {
77	          switch (key) {
78	            case "threshold":
79	              comp.threshold.value = value;
80	              break;
81	            case "ratio":
82	              comp.ratio.value = value;
83	              break;
84	            case "knee":
85	              comp.knee.value = value;
86	              break;
87	            case "attack":
88	              comp.attack.value = value;
89	              break;
90	            case "release":
91	              comp.release.value = value;
92	              break;
93	          }
94	        },
95	      });
96	
97	      return effect;
98	    },
