1	/**
2	 * Controller hook that bridges the transport audio layer to the Zustand store.
3	 * Creates and manages TransportClock, LookAheadScheduler, and Metronome.
4	 *
5	 * useTransportInit() — initialization (used only by TransportProvider)
6	 * useTransport()     — context consumer (used by all other components)
7	 */
8	
9	import { useCallback, useContext, useEffect, useRef } from "react";
10	import { useAudioEngine } from "./use-audio-engine";
11	import { createTransportClock, type TransportClock } from "./transport-clock";
12	import {
13	  createLookAheadScheduler,
14	  type LookAheadScheduler,
15	} from "./look-ahead-scheduler";
16	import { createMetronome, type Metronome } from "./metronome";
17	import {
18	  createSharedBuffers,
19	  type SharedArrayBufferLayout,
20	} from "./shared-buffer-layout";
21	import { useDawStore } from "@state/index";
22	import { TransportCtx } from "./transport-ctx";
23	
24	export type UseTransportReturn = {
25	  play(): void;
26	  pause(): void;
27	  stop(): void;
28	  seek(seconds: number): void;
29	  setBpm(bpm: number): void;
30	  setMetronomeEnabled(on: boolean): void;
31	  getTransportSAB(): SharedArrayBuffer | null;
32	  getClock(): TransportClock | null;
33	};
34	
35	/**
36	 * Initializes the transport audio stack. Used only by TransportProvider.
37	 */
38	export function useTransportInit(): UseTransportReturn {
39	  const engine = useAudioEngine();
40	  const clockRef = useRef<TransportClock | null>(null);
41	  const schedulerRef = useRef<LookAheadScheduler | null>(null);
42	  const metronomeRef = useRef<Metronome | null>(null);
43	  const sabRef = useRef<SharedArrayBufferLayout | null>(null);
44	
45	  const storePlay = useDawStore((s) => s.play);
46	  const storePause = useDawStore((s) => s.pause);
47	  const storeStop = useDawStore((s) => s.stop);
48	  const storeSetBpm = useDawStore((s) => s.setBpm);
49	  const storeSetCursor = useDawStore((s) => s.setCursor);
50	  const bpm = useDawStore((s) => s.bpm);
51	  const loopEnabled = useDawStore((s) => s.loopEnabled);
52	  const loopStart = useDawStore((s) => s.loopStart);
53	  const loopEnd = useDawStore((s) => s.loopEnd);
54	
55	  // Sync loop region from store to clock
56	  useEffect(() => {
57	    clockRef.current?.setLoop({
58	      enabled: loopEnabled,
59	      start: loopStart,
60	      end: loopEnd,
61	    });
62	  }, [loopEnabled, loopStart, loopEnd]);
63	
64	  // Initialize on mount
65	  useEffect(() => {
66	    const sab = createSharedBuffers();
67	    sabRef.current = sab;
68	
69	    const clock = createTransportClock(engine.ctx, sab.transport, bpm);
70	    clockRef.current = clock;
71	
72	    const met = createMetronome(engine.ctx);
73	    metronomeRef.current = met;
74	
75	    const scheduler = createLookAheadScheduler(
76	      engine.ctx,
77	      clock,
78	      undefined,
79	      (beatTime: number, beatNumber: number) => {
80	        const beatsPerBar = clock.getTempoMap().timeSignature.numerator;
81	        const isDownbeat = beatNumber % beatsPerBar === 0;
82	        met.scheduleTick(beatTime, isDownbeat);
83	      },
84	    );
85	    schedulerRef.current = scheduler;
86	
87	    return () => {
88	      scheduler.stop();
89	      met.dispose();
90	      clock.dispose();
91	      clockRef.current = null;
92	      schedulerRef.current = null;
93	      metronomeRef.current = null;
94	      sabRef.current = null;
95	    };
96	    // eslint-disable-next-line react-hooks/exhaustive-deps -- init once
97	  }, [engine]);
98	
99	  const play = useCallback((): void => {
100	    const clock = clockRef.current;
101	    const scheduler = schedulerRef.current;
102	    if (clock === null || scheduler === null) return;
103	    if (clock.state === "playing") return;
104	
105	    clock.play();
106	    scheduler.start();
107	    storePlay();
108	  }, [storePlay]);
109	
110	  const pause = useCallback((): void => {
111	    const clock = clockRef.current;
112	    const scheduler = schedulerRef.current;
113	    if (clock === null || scheduler === null) return;
114	    if (clock.state !== "playing") return;
115	
116	    clock.pause();
117	    scheduler.stop();
118	    storeSetCursor(clock.getCursorSeconds());
119	    storePause();
120	  }, [storePause, storeSetCursor]);
121	
122	  const stop = useCallback((): void => {
123	    const clock = clockRef.current;
124	    const scheduler = schedulerRef.current;
125	    const met = metronomeRef.current;
126	    if (clock === null || scheduler === null) return;
127	
128	    // INV-6: Guarantee silence within 10ms
129	    met?.silence();
130	    clock.stop();
131	    scheduler.stop();
132	    storeSetCursor(0);
133	    storeStop();
134	  }, [storeStop, storeSetCursor]);
135	
136	  const seek = useCallback(
137	    (seconds: number): void => {
138	      const clock = clockRef.current;
139	      if (clock === null) return;
140	
141	      clock.seek(seconds);
142	      schedulerRef.current?.sync();
143	      storeSetCursor(clock.getCursorSeconds());
144	    },
145	    [storeSetCursor],
146	  );
147	
148	  const setBpm = useCallback(
149	    (newBpm: number): void => {
150	      const clock = clockRef.current;
151	      if (clock === null) return;
152	
153	      clock.setBpm(newBpm);
154	      storeSetBpm(newBpm);
155	    },
156	    [storeSetBpm],
157	  );
158	
159	  const setMetronomeEnabled = useCallback((on: boolean): void => {
160	    metronomeRef.current?.setEnabled(on);
161	  }, []);
162	
163	  const getTransportSAB = useCallback((): SharedArrayBuffer | null => {
164	    return sabRef.current?.transport ?? null;
165	  }, []);
166	
167	  const getClock = useCallback((): TransportClock | null => {
168	    return clockRef.current;
169	  }, []);
170	
171	  return {
172	    play,
173	    pause,
174	    stop,
175	    seek,
176	    setBpm,
177	    setMetronomeEnabled,
178	    getTransportSAB,
179	    getClock,
180	  };
181	}
182	
183	/**
184	 * Context consumer hook. Must be used within a TransportProvider.
185	 */
186	export function useTransport(): UseTransportReturn {
187	  const transport = useContext(TransportCtx);
188	  if (transport === null) {
189	    throw new Error("useTransport must be used within TransportProvider");
190	  }
191	  return transport;
192	}
