1	/**
2	 * Metronome using OscillatorNode bursts scheduled via AudioContext.currentTime.
3	 * Downbeat: 1000Hz, Upbeat: 800Hz, Duration: 30ms.
4	 *
5	 * INV-6: dispose() disconnects the gain node immediately, guaranteeing
6	 * silence within one audio quantum (~3ms at 44.1kHz).
7	 */
8	
9	const DOWNBEAT_FREQ = 1000;
10	const UPBEAT_FREQ = 800;
11	const TICK_DURATION = 0.03; // 30ms
12	
13	export type Metronome = {
14	  setEnabled(on: boolean): void;
15	  setVolume(gain: number): void;
16	  scheduleTick(time: number, isDownbeat: boolean): void;
17	  silence(): void;
18	  dispose(): void;
19	};
20	
21	export function createMetronome(ctx: AudioContext): Metronome {
22	  let enabled = false;
23	  const gainNode = ctx.createGain();
24	  gainNode.gain.value = 0.5;
25	  gainNode.connect(ctx.destination);
26	
27	  return {
28	    setEnabled(on: boolean): void {
29	      enabled = on;
30	    },
31	
32	    setVolume(gain: number): void {
33	      gainNode.gain.value = Math.max(0, Math.min(1, gain));
34	    },
35	
36	    scheduleTick(time: number, isDownbeat: boolean): void {
37	      if (!enabled) return;
38	
39	      const osc = ctx.createOscillator();
40	      osc.frequency.value = isDownbeat ? DOWNBEAT_FREQ : UPBEAT_FREQ;
41	      osc.connect(gainNode);
42	      osc.start(time);
43	      osc.stop(time + TICK_DURATION);
44	      osc.onended = () => {
45	        osc.disconnect();
46	      };
47	    },
48	
49	    silence(): void {
50	      gainNode.gain.setValueAtTime(0, ctx.currentTime);
51	    },
52	
53	    dispose(): void {
54	      // Fade out to avoid pop, then disconnect
55	      gainNode.gain.setTargetAtTime(0, ctx.currentTime, 0.01);
56	      setTimeout(() => {
57	        gainNode.disconnect();
58	      }, 50);
59	    },
60	  };
61	}
