1	/**
2	 * Distortion effect using WaveShaperNode.
3	 * Three curve types: soft clip (tanh), hard clip, tube simulation.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const CURVE_SIZE = 4096;
10	
11	const PARAMS: readonly EffectParameterSchema[] = [
12	  {
13	    name: "Drive",
14	    key: "drive",
15	    min: 1,
16	    max: 100,
17	    default: 20,
18	    step: 1,
19	    unit: "",
20	  },
21	  {
22	    name: "Curve Type",
23	    key: "curveType",
24	    min: 0,
25	    max: 2,
26	    default: 0,
27	    step: 1,
28	    unit: "",
29	  },
30	  {
31	    name: "Mix",
32	    key: "mix",
33	    min: 0,
34	    max: 100,
35	    default: 50,
36	    step: 1,
37	    unit: "%",
38	  },
39	];
40	
41	function makeSoftClipCurve(drive: number): Float32Array {
42	  const curve = new Float32Array(CURVE_SIZE);
43	  const k = drive;
44	  for (let i = 0; i < CURVE_SIZE; i++) {
45	    const x = (i * 2) / CURVE_SIZE - 1;
46	    curve[i] = Math.tanh(k * x);
47	  }
48	  return curve;
49	}
50	
51	function makeHardClipCurve(drive: number): Float32Array {
52	  const curve = new Float32Array(CURVE_SIZE);
53	  const threshold = 1 / Math.max(drive, 1);
54	  for (let i = 0; i < CURVE_SIZE; i++) {
55	    const x = (i * 2) / CURVE_SIZE - 1;
56	    curve[i] = Math.max(-1, Math.min(1, x / threshold));
57	  }
58	  return curve;
59	}
60	
61	function makeTubeCurve(drive: number): Float32Array {
62	  const curve = new Float32Array(CURVE_SIZE);
63	  const k = drive * 2;
64	  for (let i = 0; i < CURVE_SIZE; i++) {
65	    const x = (i * 2) / CURVE_SIZE - 1;
66	    // Asymmetric tube-style clipping
67	    if (x >= 0) {
68	      curve[i] = 1 - Math.exp(-k * x);
69	    } else {
70	      curve[i] = -(1 - Math.exp(k * x));
71	    }
72	  }
73	  return curve;
74	}
75	
76	const curveGenerators = [
77	  makeSoftClipCurve,
78	  makeHardClipCurve,
79	  makeTubeCurve,
80	] as const;
81	
82	export function createDistortionFactory(): EffectFactory {
83	  return {
84	    definition: { id: "distortion", name: "Distortion", parameters: PARAMS },
85	    create(ctx, id) {
86	      let shaper: WaveShaperNode;
87	      let currentDrive = 20;
88	      let currentCurveType = 0;
89	      let curveTimer: ReturnType<typeof setTimeout> | undefined;
90	
91	      function updateCurve(): void {
92	        // Debounce curve recalculation during rapid knob changes
93	        clearTimeout(curveTimer);
94	        curveTimer = setTimeout(() => {
95	          const gen = curveGenerators[currentCurveType] ?? makeSoftClipCurve;
96	          shaper.curve = gen(currentDrive);
97	        }, 30);
98	      }
99	
100	      return createBaseEffect({
101	        ctx,
102	        id,
103	        typeId: "distortion",
104	        params: PARAMS,
105	        buildChain(inputNode, outputNode) {
106	          shaper = ctx.createWaveShaper();
107	          shaper.oversample = "4x";
108	          // Immediate curve on init (no debounce)
109	          const gen = curveGenerators[currentCurveType] ?? makeSoftClipCurve;
110	          shaper.curve = gen(currentDrive);
111	          inputNode.connect(shaper);
112	          shaper.connect(outputNode);
113	        },
114	        disposeChain() {
115	          clearTimeout(curveTimer);
116	          shaper.disconnect();
117	        },
118	        applyParam(key, value, setMix) {
119	          switch (key) {
120	            case "drive":
121	              currentDrive = value;
122	              updateCurve();
123	              break;
124	            case "curveType":
125	              currentCurveType = Math.round(value);
126	              updateCurve();
127	              break;
128	            case "mix":
129	              setMix(value / 100);
130	              break;
131	          }
132	        },
133	      });
134	    },
135	  };
136	}
