20	};
21	
22	export type ClipModel = {
23	  readonly id: string;
24	  readonly trackId: string;
25	  readonly sourceId: string;
26	  readonly startTime: number; // seconds on timeline
27	  readonly sourceOffset: number; // seconds into source
28	  readonly duration: number; // seconds
