1	/**
2	 * Single-BPM tempo map with BBT (Bar-Beat-Tick) conversion.
3	 * Ticks per beat: 480 (MIDI standard PPQ).
4	 * Bars and beats are 1-indexed (musician convention).
5	 */
6	
7	const TICKS_PER_BEAT = 480;
8	
9	export type TimeSignature = {
10	  readonly numerator: number;
11	  readonly denominator: number;
12	};
13	
14	export type BBT = {
15	  readonly bar: number;
16	  readonly beat: number;
17	  readonly tick: number;
18	};
19	
20	export type TempoMap = {
21	  readonly bpm: number;
22	  readonly timeSignature: TimeSignature;
23	  readonly sampleRate: number;
24	  secondsToBBT(seconds: number): BBT;
25	  bbtToSeconds(bbt: BBT): number;
26	  secondsToSamples(seconds: number): number;
27	  samplesToSeconds(samples: number): number;
28	  secondsPerBeat(): number;
29	  beatsToSeconds(beats: number): number;
30	};
31	
32	export function createTempoMap(
33	  bpm: number,
34	  timeSignature: TimeSignature,
35	  sampleRate: number,
36	): TempoMap {
37	  const spb = 60 / bpm;
38	  const beatsPerBar = timeSignature.numerator;
39	
40	  return {
41	    bpm,
42	    timeSignature,
43	    sampleRate,
44	
45	    secondsPerBeat(): number {
46	      return spb;
47	    },
48	
49	    beatsToSeconds(beats: number): number {
50	      return beats * spb;
51	    },
52	
53	    secondsToSamples(seconds: number): number {
54	      return Math.round(seconds * sampleRate);
55	    },
56	
57	    samplesToSeconds(samples: number): number {
58	      return samples / sampleRate;
59	    },
60	
61	    secondsToBBT(seconds: number): BBT {
62	      const totalBeats = seconds / spb;
63	      const wholeBeat = Math.floor(totalBeats);
64	      const fractionalBeat = totalBeats - wholeBeat;
65	
66	      const bar = Math.floor(wholeBeat / beatsPerBar) + 1;
67	      const beat = (wholeBeat % beatsPerBar) + 1;
68	      const tick = Math.floor(fractionalBeat * TICKS_PER_BEAT);
69	
70	      return { bar, beat, tick };
71	    },
72	
73	    bbtToSeconds(bbt: BBT): number {
74	      const totalBeats =
75	        (bbt.bar - 1) * beatsPerBar +
76	        (bbt.beat - 1) +
77	        bbt.tick / TICKS_PER_BEAT;
78	      return totalBeats * spb;
79	    },
80	  };
81	}
