1	/**
2	 * Voice allocator: 16-voice fixed pool with oldest-steal + 5ms crossfade.
3	 * INV-5: Fixed pool size, never grows.
4	 * MIT-H4-5: Oldest-steal with 5ms crossfade on stolen voices.
5	 * R-STA-05: Legato mode with pitch glide.
6	 *
7	 * Zero-allocation in allocate/release — no objects created at runtime.
8	 */
9	
10	/** Maximum number of concurrent voices */
11	export const MAX_VOICES = 16;
12	
13	/** Crossfade time in seconds when stealing a voice (MIT-H4-5) */
14	export const STEAL_CROSSFADE_S = 0.005;
15	
16	export type VoiceState = "idle" | "active" | "releasing" | "stealing";
17	
18	export type Voice = {
19	  state: VoiceState;
20	  note: number; // MIDI note number
21	  velocity: number; // 0..127
22	  /** Monotonically increasing counter set on each note-on for oldest-steal */
23	  age: number;
24	  /** Samples remaining in steal crossfade */
25	  stealFadeSamples: number;
26	  /** Crossfade gain multiplier for the old voice being stolen */
27	  stealFadeGain: number;
28	};
29	
30	export type VoiceAllocator = {
31	  readonly voices: readonly Voice[];
32	  /** Allocate a voice for a note-on. Returns voice index. */
33	  noteOn(note: number, velocity: number, legato: boolean): number;
34	  /** Release a voice for a note-off. Returns voice index or -1 if not found. */
35	  noteOff(note: number): number;
36	  /** Advance steal crossfade for one sample. Call once per render sample. */
37	  processStealFade(sampleRate: number): void;
38	  /** Mark a voice as idle (called when envelope finishes release). */
39	  markIdle(index: number): void;
40	  /** Reset all voices to idle. */
41	  reset(): void;
42	};
43	
44	export function createVoiceAllocator(): VoiceAllocator {
45	  let ageCounter = 0;
46	
47	  // Pre-allocate voice pool (INV-5: fixed size)
48	  const voices: Voice[] = Array.from({ length: MAX_VOICES }, () => ({
49	    state: "idle" as VoiceState,
50	    note: -1,
51	    velocity: 0,
52	    age: 0,
53	    stealFadeSamples: 0,
54	    stealFadeGain: 0,
55	  }));
56	
57	  function findIdleVoice(): number {
58	    for (let i = 0; i < MAX_VOICES; i++) {
59	      if (voices[i]!.state === "idle") return i;
60	    }
61	    return -1;
62	  }
63	
64	  function findOldestActive(): number {
65	    let oldestIdx = -1;
66	    let oldestAge = Infinity;
67	
68	    for (let i = 0; i < MAX_VOICES; i++) {
69	      const v = voices[i]!;
70	      // Prefer stealing releasing voices first
71	      if (v.state === "releasing" && v.age < oldestAge) {
72	        oldestAge = v.age;
73	        oldestIdx = i;
74	      }
75	    }
76	
77	    // If no releasing voice, steal oldest active
78	    if (oldestIdx === -1) {
79	      for (let i = 0; i < MAX_VOICES; i++) {
80	        const v = voices[i]!;
81	        if ((v.state === "active" || v.state === "stealing") && v.age < oldestAge) {
82	          oldestAge = v.age;
83	          oldestIdx = i;
84	        }
85	      }
86	    }
87	
88	    return oldestIdx;
89	  }
90	
91	  function findVoiceForNote(note: number): number {
92	    for (let i = 0; i < MAX_VOICES; i++) {
93	      const v = voices[i]!;
94	      if (v.note === note && (v.state === "active" || v.state === "releasing")) {
95	        return i;
96	      }
97	    }
98	    return -1;
99	  }
100	
101	  const allocator: VoiceAllocator = {
102	    voices,
103	
104	    noteOn(note: number, velocity: number, legato: boolean): number {
105	      ageCounter++;
106	
107	      // In legato mode, reuse the same voice if a note is already playing
108	      if (legato) {
109	        const existing = findVoiceForNote(note);
110	        if (existing !== -1) {
111	          const v = voices[existing]!;
112	          v.note = note;
113	          v.velocity = velocity;
114	          v.age = ageCounter;
115	          v.state = "active";
116	          return existing;
117	        }
118	        // Find any active voice for legato pitch change
119	        for (let i = 0; i < MAX_VOICES; i++) {
120	          if (voices[i]!.state === "active") {
121	            const v = voices[i]!;
122	            v.note = note;
123	            v.velocity = velocity;
124	            v.age = ageCounter;
125	            return i;
126	          }
127	        }
128	      }
129	
130	      // Try idle voice first
131	      let idx = findIdleVoice();
132	
133	      if (idx === -1) {
134	        // All voices busy — steal oldest (MIT-H4-5)
135	        idx = findOldestActive();
136	        if (idx !== -1) {
137	          const v = voices[idx]!;
138	          v.state = "stealing";
139	          v.stealFadeSamples = 0; // Will be set by caller based on sampleRate
140	          v.stealFadeGain = 1;
141	        }
142	      }
143	
144	      if (idx === -1) {
145	        // Shouldn't happen with MAX_VOICES > 0, but safety
146	        idx = 0;
147	      }
148	
149	      const v = voices[idx]!;
150	      v.note = note;
151	      v.velocity = velocity;
152	      v.age = ageCounter;
153	      v.state = "active";
154	      v.stealFadeSamples = 0;
155	      v.stealFadeGain = 0;
156	
157	      return idx;
158	    },
159	
160	    noteOff(note: number): number {
161	      const idx = findVoiceForNote(note);
162	      if (idx === -1) return -1;
163	
164	      voices[idx]!.state = "releasing";
165	      return idx;
166	    },
167	
168	    processStealFade(sampleRate: number): void {
169	      const crossfadeSamples = Math.floor(STEAL_CROSSFADE_S * sampleRate);
170	
171	      for (let i = 0; i < MAX_VOICES; i++) {
172	        const v = voices[i]!;
173	        if (v.state === "stealing") {
174	          v.stealFadeSamples++;
175	          v.stealFadeGain = Math.max(
176	            0,
177	            1 - v.stealFadeSamples / crossfadeSamples,
178	          );
179	          if (v.stealFadeSamples >= crossfadeSamples) {
180	            v.state = "active";
181	            v.stealFadeGain = 0;
182	            v.stealFadeSamples = 0;
183	          }
184	        }
185	      }
186	    },
