      const crossfadeSamples = Math.floor(STEAL_CROSSFADE_S * sampleRate);

      for (let i = 0; i < MAX_VOICES; i++) {
        const v = voices[i]!;
        if (v.state === "stealing") {
          v.stealFadeSamples++;
          v.stealFadeGain = Math.max(
            0,
            1 - v.stealFadeSamples / crossfadeSamples,
          );
          if (v.stealFadeSamples >= crossfadeSamples) {
            v.state = "active";
            v.stealFadeGain = 0;
            v.stealFadeSamples = 0;
          }
        }
      }
    },

    markIdle(index: number): void {
      if (index >= 0 && index < MAX_VOICES) {
        const v = voices[index]!;
        v.state = "idle";
        v.note = -1;
        v.velocity = 0;
        v.stealFadeSamples = 0;
        v.stealFadeGain = 0;
      }
    },

    reset(): void {
      ageCounter = 0;
      for (let i = 0; i < MAX_VOICES; i++) {
        const v = voices[i]!;
        v.state = "idle";
        v.note = -1;
        v.velocity = 0;
        v.age = 0;
        v.stealFadeSamples = 0;
        v.stealFadeGain = 0;
      }
    },
  };

  return allocator;
}

