  filter: BiquadFilter;
  targetFreq: number;
  currentFreq: number;
  velocity: number;
};

function createVoiceData(): VoiceData {
  return {
    osc1: createPolyBLEPOsc("saw"),
    osc2: createPolyBLEPOsc("saw"),
    ampEnv: createADSREnvelope(),
    filterEnv: createADSREnvelope(),
    filter: createBiquadFilter("lowpass"),
    targetFreq: 440,
    currentFreq: 440,
    velocity: 0,
  };
}

class SynthProcessor extends AudioWorkletProcessor {
  private allocator: VoiceAllocator;
  private voiceData: VoiceData[];
  private lfo1: LFO;
  private lfo2: LFO;
  private params: SynthParameterMap;
  // Pre-allocated coefficients object to avoid allocation in process()
  private coeffs: BiquadCoeffs;
  private alive = true;

  constructor() {
    super();

    this.allocator = createVoiceAllocator();
    this.voiceData = Array.from({ length: MAX_VOICES }, () => createVoiceData());
    this.lfo1 = createLFO("sine");
    this.lfo2 = createLFO("sine");
    this.params = { ...DEFAULT_SYNTH_PARAMS };
    this.coeffs = { b0: 0, b1: 0, b2: 0, a0: 1, a1: 0, a2: 0 };

    this.port.onmessage = (e: MessageEvent) => {
      this.handleMessage(e.data as SynthVoiceCommand);
    };
  }

  private handleMessage(cmd: SynthVoiceCommand): void {
    switch (cmd.type) {
      case "noteOn": {
        const legato = cmd.legato;
        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
        const vd = this.voiceData[idx]!;
        const voice = this.allocator.voices[idx]!;

        const octave1 = this.params.osc1Octave;
        const octave2 = this.params.osc2Octave;
        const detune1 = this.params.osc1Detune;
        const detune2 = this.params.osc2Detune;

        const baseFreq = midiToFreq(cmd.note);
        vd.targetFreq = baseFreq;
        vd.velocity = cmd.velocity / 127;

        if (!legato || vd.currentFreq === 0) {
          vd.currentFreq = baseFreq;
        }

        // Reset oscillators for non-legato
        if (!legato) {
          vd.osc1.reset();
          vd.osc2.reset();
          vd.filter.reset();
        }

        // Set oscillator types
        vd.osc1.type = this.params.osc1Type;
        vd.osc2.type = this.params.osc2Type;
        vd.filter.type = this.params.filterType;

        // Trigger envelopes
        vd.ampEnv.gate(legato);
        vd.filterEnv.gate(legato);
        break;
      }

      case "noteOff": {
        const idx = this.allocator.noteOff(cmd.note);
        if (idx >= 0) {
          const vd = this.voiceData[idx]!;
          vd.ampEnv.release();
          vd.filterEnv.release();
        }
        break;
      }

      case "allNotesOff":
        for (let i = 0; i < MAX_VOICES; i++) {
          this.voiceData[i]!.ampEnv.release();
          this.voiceData[i]!.filterEnv.release();
        }
        break;

      case "setParam":
        this.setParamValue(cmd.key, cmd.value);
        break;
    }
  }

  private setParamValue(key: string, value: number): void {
    switch (key) {
      case "osc1Type":
        this.params.osc1Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
        break;
      case "osc2Type":
        this.params.osc2Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
        break;
      case "filterType": {
        const ft = FILTER_TYPES[Math.round(value)] ?? "lowpass";
        this.params.filterType = ft;
        for (let i = 0; i < MAX_VOICES; i++) {
          this.voiceData[i]!.filter.type = ft;
        }
        break;
      }
      case "lfo1Shape":
        this.params.lfo1Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
        this.lfo1.shape = this.params.lfo1Shape;
        break;
      case "lfo2Shape":
        this.params.lfo2Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
        this.lfo2.shape = this.params.lfo2Shape;
        break;
      default:
        // Numeric params
        (this.params as Record<string, unknown>)[key] = value;
        break;
    }
  }

  process(
    _inputs: Float32Array[][],
    outputs: Float32Array[][],
    _parameters: Record<string, Float32Array>,
  ): boolean {
    const output = outputs[0];
    if (!output) return this.alive;

    const outL = output[0];
    const outR = output[1] ?? output[0];
    if (!outL || !outR) return this.alive;

    const numSamples = outL.length;
    const sr = sampleRate;
    const p = this.params;

    const ampParams: ADSRParams = {
      attack: p.ampAttack,
      decay: p.ampDecay,
      sustain: p.ampSustain,
      release: p.ampRelease,
    };

    const filterParams: ADSRParams = {
      attack: p.filterAttack,
      decay: p.filterDecay,
      sustain: p.filterSustain,
      release: p.filterRelease,
    };

    for (let s = 0; s < numSamples; s++) {
      // LFOs run once per sample (shared across all voices)
      const lfo1Val = this.lfo1.process(p.lfo1Rate, sr);
      const lfo2Val = this.lfo2.process(p.lfo2Rate, sr);

      let mixL = 0;
      let mixR = 0;

      for (let v = 0; v < MAX_VOICES; v++) {
        const voice = this.allocator.voices[v]!;
        if (voice.state === "idle") continue;

        const vd = this.voiceData[v]!;

        // Pitch glide (R-STA-05)
        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
        } else {
          vd.currentFreq = vd.targetFreq;
        }

        const baseFreq = vd.currentFreq;

        // LFO1 -> pitch modulation (in semitones)
        const pitchMod = lfo1Val * p.lfo1Depth * 2; // up to 2 semitones
        const pitchMultiplier = Math.pow(2, pitchMod / 12);

        // Oscillator frequencies with octave, detune, and modulation
        const freq1 =
          baseFreq *
          Math.pow(2, p.osc1Octave) *
          Math.pow(2, p.osc1Detune / 1200) *
          pitchMultiplier;
        const freq2 =
          baseFreq *
          Math.pow(2, p.osc2Octave) *
          Math.pow(2, p.osc2Detune / 1200) *
          pitchMultiplier;

        // Generate oscillators
        const osc1Out = vd.osc1.next(freq1, sr) * p.osc1Level;
        const osc2Out = vd.osc2.next(freq2, sr) * p.osc2Level;
        let sample = osc1Out + osc2Out;

        // Filter envelope -> cutoff modulation
        const filterEnvVal = vd.filterEnv.process(filterParams, sr);
        const envCutoffMod = filterEnvVal * p.filterEnvDepth; // semitones

        // LFO1 -> cutoff modulation
        const lfoCutoffMod = lfo1Val * p.lfo1Depth * 12; // up to 12 semitones

        // Velocity -> filter modulation
        const velCutoffMod = vd.velocity * 24; // up to 24 semitones

        // Apply all cutoff modulations (semitones from base cutoff)
        const totalCutoffMod = envCutoffMod + lfoCutoffMod + velCutoffMod;
        const modulatedCutoff =
          p.filterCutoff * Math.pow(2, totalCutoffMod / 12);
        const clampedCutoff = Math.min(Math.max(modulatedCutoff, 20), sr / 2 - 100);

        // Compute filter coefficients (reuses pre-allocated object)
        const c = computeBiquadCoeffs(p.filterType, clampedCutoff, p.filterResonance, sr);
        this.coeffs.b0 = c.b0;
        this.coeffs.b1 = c.b1;
        this.coeffs.b2 = c.b2;
        this.coeffs.a0 = c.a0;
        this.coeffs.a1 = c.a1;
        this.coeffs.a2 = c.a2;

        // Apply filter
        sample = vd.filter.process(sample, this.coeffs);

        // Amplitude envelope
        const ampLevel = vd.ampEnv.process(ampParams, sr);

        // LFO2 -> amplitude modulation (tremolo)
        const ampMod = 1 + lfo2Val * p.lfo2Depth * 0.5; // 0.5..1.5 range

        // Velocity -> amplitude
        const velAmp = 0.5 + vd.velocity * 0.5; // velocity scales 0.5..1

        sample *= ampLevel * ampMod * velAmp * p.masterGain;

        // Voice steal crossfade
        if (voice.state === "stealing") {
          // Fade handled by allocator — but output is the new note
        }

        // Mark idle when envelope finishes
        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
          this.allocator.markIdle(v);
          continue;
        }

        mixL += sample;
        mixR += sample;
      }

      // Process steal fades
      this.allocator.processStealFade(sr);

      outL[s] = mixL;
      outR[s] = mixR;
    }

    return this.alive;
  }
}

registerProcessor("synth-processor", SynthProcessor);

/**
 * Voice allocator: 16-voice fixed pool with oldest-steal + 5ms crossfade.
 * INV-5: Fixed pool size, never grows.
 * MIT-H4-5: Oldest-steal with 5ms crossfade on stolen voices.
 * R-STA-05: Legato mode with pitch glide.
 *
 * Zero-allocation in allocate/release — no objects created at runtime.
 */

/** Maximum number of concurrent voices */
export const MAX_VOICES = 16;

/** Crossfade time in seconds when stealing a voice (MIT-H4-5) */
export const STEAL_CROSSFADE_S = 0.005;

export type VoiceState = "idle" | "active" | "releasing" | "stealing";

export type Voice = {
  state: VoiceState;
  note: number; // MIDI note number
  velocity: number; // 0..127
  /** Monotonically increasing counter set on each note-on for oldest-steal */
  age: number;
  /** Samples remaining in steal crossfade */
  stealFadeSamples: number;
  /** Crossfade gain multiplier for the old voice being stolen */
  stealFadeGain: number;
};

export type VoiceAllocator = {
  readonly voices: readonly Voice[];
  /** Allocate a voice for a note-on. Returns voice index. */
  noteOn(note: number, velocity: number, legato: boolean): number;
  /** Release a voice for a note-off. Returns voice index or -1 if not found. */
  noteOff(note: number): number;
  /** Advance steal crossfade for one sample. Call once per render sample. */
  processStealFade(sampleRate: number): void;
  /** Mark a voice as idle (called when envelope finishes release). */
  markIdle(index: number): void;
  /** Reset all voices to idle. */
  reset(): void;
};

/** Safe array access that throws on out-of-bounds (pool is fixed-size). */
function v(voices: Voice[], i: number): Voice {
  const voice = voices[i];
  if (!voice) throw new Error(`Voice index ${i} out of bounds`);
  return voice;
}

export function createVoiceAllocator(): VoiceAllocator {
  let ageCounter = 0;

  // Pre-allocate voice pool (INV-5: fixed size)
  const voices: Voice[] = Array.from({ length: MAX_VOICES }, () => ({
    state: "idle" as VoiceState,
    note: -1,
    velocity: 0,
    age: 0,
    stealFadeSamples: 0,
    stealFadeGain: 0,
  }));

  function findIdleVoice(): number {
    for (let i = 0; i < MAX_VOICES; i++) {
      if (v(voices, i).state === "idle") return i;
    }
    return -1;
  }

  function findOldestActive(): number {
    let oldestIdx = -1;
    let oldestAge = Infinity;

    for (let i = 0; i < MAX_VOICES; i++) {
      const voice = v(voices, i);
      if (voice.state === "releasing" && voice.age < oldestAge) {
        oldestAge = voice.age;
        oldestIdx = i;
      }
    }

    if (oldestIdx === -1) {
      for (let i = 0; i < MAX_VOICES; i++) {
        const voice = v(voices, i);
        if ((voice.state === "active" || voice.state === "stealing") && voice.age < oldestAge) {
          oldestAge = voice.age;
          oldestIdx = i;
        }
      }
    }

    return oldestIdx;
  }

  function findVoiceForNote(note: number): number {
    for (let i = 0; i < MAX_VOICES; i++) {
      const voice = v(voices, i);
      if (voice.note === note && (voice.state === "active" || voice.state === "releasing")) {
        return i;
      }
    }
    return -1;
  }

  const allocator: VoiceAllocator = {
    voices,

    noteOn(note: number, velocity: number, legato: boolean): number {
      ageCounter++;

      if (legato) {
        const existing = findVoiceForNote(note);
        if (existing !== -1) {
          const voice = v(voices, existing);
          voice.note = note;
          voice.velocity = velocity;
          voice.age = ageCounter;
          voice.state = "active";
          return existing;
        }
        for (let i = 0; i < MAX_VOICES; i++) {
          const voice = v(voices, i);
          if (voice.state === "active") {
            voice.note = note;
            voice.velocity = velocity;
            voice.age = ageCounter;
            return i;
          }
        }
      }

      let idx = findIdleVoice();

      if (idx === -1) {
        idx = findOldestActive();
        if (idx !== -1) {
          const voice = v(voices, idx);
          voice.state = "stealing";
          voice.stealFadeSamples = 0;
          voice.stealFadeGain = 1;
        }
      }

      if (idx === -1) {
        idx = 0;
      }

      const voice = v(voices, idx);
      voice.note = note;
      voice.velocity = velocity;
      voice.age = ageCounter;
      voice.state = "active";
      voice.stealFadeSamples = 0;
      voice.stealFadeGain = 0;

      return idx;
    },

    noteOff(note: number): number {
      const idx = findVoiceForNote(note);
      if (idx === -1) return -1;

      v(voices, idx).state = "releasing";
      return idx;
    },

    processStealFade(sampleRate: number): void {
      const crossfadeSamples = Math.floor(STEAL_CROSSFADE_S * sampleRate);

      for (let i = 0; i < MAX_VOICES; i++) {
        const voice = v(voices, i);
        if (voice.state === "stealing") {
          voice.stealFadeSamples++;
          voice.stealFadeGain = Math.max(
            0,
            1 - voice.stealFadeSamples / crossfadeSamples,
          );
          if (voice.stealFadeSamples >= crossfadeSamples) {
            voice.state = "active";
            voice.stealFadeGain = 0;
            voice.stealFadeSamples = 0;
          }
        }
      }
    },

    markIdle(index: number): void {
      if (index >= 0 && index < MAX_VOICES) {
        const voice = v(voices, index);
        voice.state = "idle";
        voice.note = -1;
        voice.velocity = 0;
        voice.stealFadeSamples = 0;
        voice.stealFadeGain = 0;
      }
    },

    reset(): void {
      ageCounter = 0;
      for (let i = 0; i < MAX_VOICES; i++) {
        const voice = v(voices, i);
        voice.state = "idle";
        voice.note = -1;
        voice.velocity = 0;
        voice.age = 0;
        voice.stealFadeSamples = 0;
        voice.stealFadeGain = 0;
      }
    },
  };

  return allocator;
}

import { describe, it, expect } from "vitest";
import {
  createVoiceAllocator,
  MAX_VOICES,
  STEAL_CROSSFADE_S,
  type Voice,
} from "./voice-allocator";

const SR = 48000;

/** Safe voice access for tests */
function at(voices: readonly Voice[], i: number): Voice {
  const voice = voices[i];
  if (!voice) throw new Error(`Index ${i} out of bounds`);
  return voice;
}

describe("Voice Allocator", () => {
  it("allocates to idle voices", () => {
    const alloc = createVoiceAllocator();
    const idx = alloc.noteOn(60, 100, false);
    expect(idx).toBeGreaterThanOrEqual(0);
    expect(idx).toBeLessThan(MAX_VOICES);
    expect(at(alloc.voices, idx).state).toBe("active");
    expect(at(alloc.voices, idx).note).toBe(60);
    expect(at(alloc.voices, idx).velocity).toBe(100);
  });

  it("has fixed pool of 16 voices (INV-5)", () => {
    const alloc = createVoiceAllocator();
    expect(alloc.voices.length).toBe(16);
  });

  it("fills all 16 voices before stealing", () => {
    const alloc = createVoiceAllocator();
    const allocated = new Set<number>();

    for (let i = 0; i < MAX_VOICES; i++) {
      const idx = alloc.noteOn(60 + i, 100, false);
      allocated.add(idx);
    }

    expect(allocated.size).toBe(MAX_VOICES);
  });

  it("steals oldest voice when pool is full (MIT-H4-5)", () => {
    const alloc = createVoiceAllocator();

    for (let i = 0; i < MAX_VOICES; i++) {
      alloc.noteOn(60 + i, 100, false);
    }

    const stolenIdx = alloc.noteOn(90, 100, false);
    expect(at(alloc.voices, stolenIdx).note).toBe(90);
  });

  it("prefers stealing releasing voices over active", () => {
    const alloc = createVoiceAllocator();

    for (let i = 0; i < MAX_VOICES; i++) {
      alloc.noteOn(60 + i, 100, false);
    }

    const releasedIdx = alloc.noteOff(60);
    expect(releasedIdx).toBeGreaterThanOrEqual(0);
    expect(at(alloc.voices, releasedIdx).state).toBe("releasing");

    const newIdx = alloc.noteOn(90, 100, false);
    expect(newIdx).toBe(releasedIdx);
  });

  it("noteOff transitions voice to releasing", () => {
    const alloc = createVoiceAllocator();
    alloc.noteOn(60, 100, false);
    const idx = alloc.noteOff(60);
    expect(idx).toBeGreaterThanOrEqual(0);
    expect(at(alloc.voices, idx).state).toBe("releasing");
  });

  it("noteOff returns -1 for unknown note", () => {
    const alloc = createVoiceAllocator();
    expect(alloc.noteOff(99)).toBe(-1);
  });

  it("markIdle returns voice to pool", () => {
    const alloc = createVoiceAllocator();
    const idx = alloc.noteOn(60, 100, false);
    alloc.markIdle(idx);
    expect(at(alloc.voices, idx).state).toBe("idle");
    expect(at(alloc.voices, idx).note).toBe(-1);
  });

  it("steal crossfade lasts 5ms (MIT-H4-5)", () => {
    const expectedSamples = Math.floor(STEAL_CROSSFADE_S * SR);
    expect(expectedSamples).toBe(240);
  });

  it("legato mode reuses active voice", () => {
    const alloc = createVoiceAllocator();
    const idx1 = alloc.noteOn(60, 100, false);
    const idx2 = alloc.noteOn(64, 100, true);

    expect(idx2).toBe(idx1);
    expect(at(alloc.voices, idx2).note).toBe(64);
    expect(at(alloc.voices, idx2).state).toBe("active");
  });

  it("reset returns all voices to idle", () => {
    const alloc = createVoiceAllocator();
    for (let i = 0; i < 5; i++) {
      alloc.noteOn(60 + i, 100, false);
    }
    alloc.reset();

    for (let i = 0; i < MAX_VOICES; i++) {
      expect(at(alloc.voices, i).state).toBe("idle");
      expect(at(alloc.voices, i).note).toBe(-1);
    }
  });

  it("processStealFade decrements crossfade gain", () => {
    const alloc = createVoiceAllocator();

    for (let i = 0; i < MAX_VOICES; i++) {
      alloc.noteOn(60 + i, 100, false);
    }

    alloc.noteOn(90, 100, false);

    const crossfadeSamples = Math.floor(STEAL_CROSSFADE_S * SR);
    for (let i = 0; i < crossfadeSamples + 10; i++) {
      alloc.processStealFade(SR);
    }

    for (let i = 0; i < MAX_VOICES; i++) {
      expect(at(alloc.voices, i).state).not.toBe("stealing");
    }
  });
});

/**
 * Synthesizer AudioWorklet processor.
 * Runs on the audio rendering thread — zero allocations in process().
 *
 * Architecture: 16 fixed voices, each with:
 * - 2 PolyBLEP oscillators
 * - Biquad filter (LP/HP/BP)
 * - ADSR amplitude envelope
 * - ADSR filter envelope
 * Shared: 2 LFOs, hardwired modulation matrix.
 *
 * INV-3/NFR-14: Zero-allocation process().
 * MIT-H4-5: Oldest-steal with 5ms crossfade.
 * MIT-H4-6: 2ms minimum release time.
 * R-STA-05: Legato mode with pitch glide.
 */

import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
import { createADSREnvelope, type ADSREnvelope, type ADSRParams } from "./dsp/adsr";
import {
  computeBiquadCoeffs,
  createBiquadFilter,
  type BiquadFilter,
  type BiquadCoeffs,
} from "./dsp/biquad-coeffs";
import { createLFO, type LFO } from "./dsp/lfo";
import {
  createVoiceAllocator,
  type VoiceAllocator,
  MAX_VOICES,
} from "./dsp/voice-allocator";
import {
  midiToFreq,
  WAVEFORM_TYPES,
  FILTER_TYPES,
  LFO_SHAPES,
  type SynthVoiceCommand,
  type SynthParameterMap,
  DEFAULT_SYNTH_PARAMS,
} from "./synth-types";

// ─── AudioWorklet globals (not in TypeScript's lib by default) ───
declare const sampleRate: number;
declare class AudioWorkletProcessor {
  readonly port: MessagePort;
  constructor();
  process(
    inputs: Float32Array[][],
    outputs: Float32Array[][],
    parameters: Record<string, Float32Array>,
  ): boolean;
}
declare function registerProcessor(
  name: string,
  ctor: typeof AudioWorkletProcessor,
): void;

// ─── Per-Voice State (pre-allocated) ───

type VoiceData = {
  osc1: PolyBLEPOsc;
  osc2: PolyBLEPOsc;
  ampEnv: ADSREnvelope;
  filterEnv: ADSREnvelope;
  filter: BiquadFilter;
  targetFreq: number;
  currentFreq: number;
  velocity: number;
};

function createVoiceData(): VoiceData {
  return {
    osc1: createPolyBLEPOsc("saw"),
    osc2: createPolyBLEPOsc("saw"),
    ampEnv: createADSREnvelope(),
    filterEnv: createADSREnvelope(),
    filter: createBiquadFilter("lowpass"),
    targetFreq: 440,
    currentFreq: 440,
    velocity: 0,
  };
}

/** Safe access to pre-allocated arrays */
function at<T>(arr: T[], i: number): T {
  const val = arr[i];
  if (val === undefined) throw new Error(`Index ${i} out of bounds`);
  return val;
}

class SynthProcessor extends AudioWorkletProcessor {
  private allocator: VoiceAllocator;
  private voiceData: VoiceData[];
  private lfo1: LFO;
  private lfo2: LFO;
  private params: SynthParameterMap;
  private coeffs: BiquadCoeffs;
  private alive = true;

  constructor() {
    super();

    this.allocator = createVoiceAllocator();
    this.voiceData = Array.from({ length: MAX_VOICES }, () => createVoiceData());
    this.lfo1 = createLFO("sine");
    this.lfo2 = createLFO("sine");
    this.params = { ...DEFAULT_SYNTH_PARAMS };
    this.coeffs = { b0: 0, b1: 0, b2: 0, a0: 1, a1: 0, a2: 0 };

    this.port.onmessage = (e: MessageEvent) => {
      this.handleMessage(e.data as SynthVoiceCommand);
    };
  }

  private handleMessage(cmd: SynthVoiceCommand): void {
    switch (cmd.type) {
      case "noteOn": {
        const legato = cmd.legato;
        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
        const vd = at(this.voiceData, idx);

        const baseFreq = midiToFreq(cmd.note);
        vd.targetFreq = baseFreq;
        vd.velocity = cmd.velocity / 127;

        if (!legato || vd.currentFreq === 0) {
          vd.currentFreq = baseFreq;
        }

        if (!legato) {
          vd.osc1.reset();
          vd.osc2.reset();
          vd.filter.reset();
        }

        vd.osc1.type = this.params.osc1Type;
        vd.osc2.type = this.params.osc2Type;
        vd.filter.type = this.params.filterType;

        vd.ampEnv.gate(legato);
        vd.filterEnv.gate(legato);
        break;
      }

      case "noteOff": {
        const idx = this.allocator.noteOff(cmd.note);
        if (idx >= 0) {
          const vd = at(this.voiceData, idx);
          vd.ampEnv.release();
          vd.filterEnv.release();
        }
        break;
      }

      case "allNotesOff":
        for (let i = 0; i < MAX_VOICES; i++) {
          at(this.voiceData, i).ampEnv.release();
          at(this.voiceData, i).filterEnv.release();
        }
        break;

      case "setParam":
        this.setParamValue(cmd.key, cmd.value);
        break;
    }
  }

  private setParamValue(key: string, value: number): void {
    switch (key) {
      case "osc1Type":
        this.params.osc1Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
        break;
      case "osc2Type":
        this.params.osc2Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
        break;
      case "filterType": {
        const ft = FILTER_TYPES[Math.round(value)] ?? "lowpass";
        this.params.filterType = ft;
        for (let i = 0; i < MAX_VOICES; i++) {
          at(this.voiceData, i).filter.type = ft;
        }
        break;
      }
      case "lfo1Shape":
        this.params.lfo1Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
        this.lfo1.shape = this.params.lfo1Shape;
        break;
      case "lfo2Shape":
        this.params.lfo2Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
        this.lfo2.shape = this.params.lfo2Shape;
        break;
      default:
        (this.params as Record<string, unknown>)[key] = value;
        break;
    }
  }

  process(
    _inputs: Float32Array[][],
    outputs: Float32Array[][],
    _parameters: Record<string, Float32Array>,
  ): boolean {
    const output = outputs[0];
    if (!output) return this.alive;

    const outL = output[0];
    const outR = output[1] ?? output[0];
    if (!outL || !outR) return this.alive;

    const numSamples = outL.length;
    const sr = sampleRate;
    const p = this.params;

    const ampParams: ADSRParams = {
      attack: p.ampAttack,
      decay: p.ampDecay,
      sustain: p.ampSustain,
      release: p.ampRelease,
    };

    const filterParams: ADSRParams = {
      attack: p.filterAttack,
      decay: p.filterDecay,
      sustain: p.filterSustain,
      release: p.filterRelease,
    };

    for (let s = 0; s < numSamples; s++) {
      const lfo1Val = this.lfo1.process(p.lfo1Rate, sr);
      const lfo2Val = this.lfo2.process(p.lfo2Rate, sr);

      let mixL = 0;
      let mixR = 0;

      for (let vi = 0; vi < MAX_VOICES; vi++) {
        const voice = at(this.allocator.voices as unknown[], vi) as {
          state: string;
        };
        if (voice.state === "idle") continue;

        const vd = at(this.voiceData, vi);

        // Pitch glide (R-STA-05)
        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
        } else {
          vd.currentFreq = vd.targetFreq;
        }

        const baseFreq = vd.currentFreq;

        // LFO1 -> pitch modulation (in semitones)
        const pitchMod = lfo1Val * p.lfo1Depth * 2;
        const pitchMultiplier = Math.pow(2, pitchMod / 12);

        const freq1 =
          baseFreq *
          Math.pow(2, p.osc1Octave) *
          Math.pow(2, p.osc1Detune / 1200) *
          pitchMultiplier;
        const freq2 =
          baseFreq *
          Math.pow(2, p.osc2Octave) *
          Math.pow(2, p.osc2Detune / 1200) *
          pitchMultiplier;

        const osc1Out = vd.osc1.next(freq1, sr) * p.osc1Level;
        const osc2Out = vd.osc2.next(freq2, sr) * p.osc2Level;
        let sample = osc1Out + osc2Out;

        // Filter envelope -> cutoff modulation
        const filterEnvVal = vd.filterEnv.process(filterParams, sr);
        const envCutoffMod = filterEnvVal * p.filterEnvDepth;

        // LFO1 -> cutoff modulation
        const lfoCutoffMod = lfo1Val * p.lfo1Depth * 12;

        // Velocity -> filter modulation
        const velCutoffMod = vd.velocity * 24;

        const totalCutoffMod = envCutoffMod + lfoCutoffMod + velCutoffMod;
        const modulatedCutoff =
          p.filterCutoff * Math.pow(2, totalCutoffMod / 12);
        const clampedCutoff = Math.min(Math.max(modulatedCutoff, 20), sr / 2 - 100);

        const c = computeBiquadCoeffs(p.filterType, clampedCutoff, p.filterResonance, sr);
        this.coeffs.b0 = c.b0;
        this.coeffs.b1 = c.b1;
        this.coeffs.b2 = c.b2;
        this.coeffs.a0 = c.a0;
        this.coeffs.a1 = c.a1;
        this.coeffs.a2 = c.a2;

        sample = vd.filter.process(sample, this.coeffs);

        // Amplitude envelope
        const ampLevel = vd.ampEnv.process(ampParams, sr);

        // LFO2 -> amplitude modulation (tremolo)
        const ampMod = 1 + lfo2Val * p.lfo2Depth * 0.5;

        // Velocity -> amplitude
        const velAmp = 0.5 + vd.velocity * 0.5;

        sample *= ampLevel * ampMod * velAmp * p.masterGain;

        // Mark idle when envelope finishes
        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
          this.allocator.markIdle(vi);
          continue;
        }

        mixL += sample;
        mixR += sample;
      }

      this.allocator.processStealFade(sr);

      outL[s] = mixL;
      outR[s] = mixR;
    }

    return this.alive;
  }
}

