        onNoteOn(note, 100);
      }
    },
    [onNoteOn],
  );

  const handleMouseUp = useCallback(
    (note: number) => {
      if (activeNotes.current.has(note)) {
        activeNotes.current.delete(note);
        onNoteOff(note);
      }
    },
    [onNoteOff],
  );

  const handleMouseLeave = useCallback(
    (note: number) => {
      if (activeNotes.current.has(note)) {
        activeNotes.current.delete(note);
        onNoteOff(note);
      }
    },
    [onNoteOff],
  );

  // Build white and black keys
  const whiteKeys: React.JSX.Element[] = [];
  const blackKeys: React.JSX.Element[] = [];

  let whiteIndex = 0;

  for (let octave = 0; octave < NUM_OCTAVES; octave++) {
    for (const offset of WHITE_KEY_OFFSETS) {
      const note = OCTAVE_START + octave * 12 + offset;
      const x = whiteIndex * WHITE_KEY_WIDTH;
      whiteKeys.push(
        <div
          key={`w-${note}`}
          data-testid={`key-${note}`}
          onMouseDown={() => handleMouseDown(note)}
          onMouseUp={() => handleMouseUp(note)}
          onMouseLeave={() => handleMouseLeave(note)}
          style={{
            position: "absolute",
            left: x,
            top: 0,
            width: WHITE_KEY_WIDTH,
            height: WHITE_KEY_HEIGHT,
            backgroundColor: tokens.color.white,
            border: `${tokens.border.width}px solid ${tokens.color.black}`,
            cursor: "pointer",
            userSelect: "none",
            zIndex: 1,
          }}
        />,
      );
      whiteIndex++;
    }

    for (let bi = 0; bi < BLACK_KEY_OFFSETS.length; bi++) {
      const offset = BLACK_KEY_OFFSETS[bi]!;
      const pos = BLACK_KEY_POSITIONS[bi]!;
      const note = OCTAVE_START + octave * 12 + offset;
      const x =
        (octave * WHITE_KEY_OFFSETS.length + pos) * WHITE_KEY_WIDTH +
        (WHITE_KEY_WIDTH - BLACK_KEY_WIDTH) / 2;

      blackKeys.push(
        <div
          key={`b-${note}`}
          data-testid={`key-${note}`}
          onMouseDown={() => handleMouseDown(note)}
          onMouseUp={() => handleMouseUp(note)}
          onMouseLeave={() => handleMouseLeave(note)}
          style={{
            position: "absolute",
            left: x,
            top: 0,
            width: BLACK_KEY_WIDTH,
            height: BLACK_KEY_HEIGHT,
            backgroundColor: tokens.color.black,
            border: `${tokens.border.width}px solid ${tokens.color.gray700}`,
            cursor: "pointer",
            userSelect: "none",
            zIndex: 2,
          }}
        />,
      );
    }
  }

  const totalWidth = whiteIndex * WHITE_KEY_WIDTH;

  return (
    <div
      data-testid="virtual-keyboard"
      style={{
        position: "relative",
        width: totalWidth,
        height: WHITE_KEY_HEIGHT,
        flexShrink: 0,
      }}
    >
      {whiteKeys}
      {blackKeys}
    </div>
  );
}

