1	/**
2	 * PolyBLEP (Polynomial Bandlimited Step) antialiased oscillator.
3	 * Corrects discontinuities in naive waveforms to suppress aliasing.
4	 * O(1) per sample, no lookup tables, pitch-agile.
5	 */
6	
7	/** Waveform types supported by the PolyBLEP oscillator */
8	export type WaveformType = "sine" | "saw" | "square" | "triangle";
9	
10	/** PolyBLEP correction term for a discontinuity at phase = 0 */
11	function polyblep(t: number, dt: number): number {
12	  if (t < dt) {
13	    const u = t / dt;
14	    return u + u - u * u - 1;
15	  }
16	  if (t > 1 - dt) {
17	    const u = (t - 1) / dt;
18	    return u * u + u + u + 1;
19	  }
20	  return 0;
21	}
22	
23	/**
24	 * Stateful PolyBLEP oscillator.
25	 * Call `next()` once per sample to get the output in [-1, 1].
26	 * Mutates phase internally — zero-allocation in the hot path.
27	 */
28	export type PolyBLEPOsc = {
29	  phase: number;
30	  type: WaveformType;
31	  /** Advance one sample. Returns output in [-1, 1]. */
32	  next(frequency: number, sampleRate: number): number;
33	  /** Reset phase (e.g. for hard sync). */
34	  reset(): void;
35	};
36	
37	export function createPolyBLEPOsc(type: WaveformType = "saw"): PolyBLEPOsc {
38	  let phase = 0;
39	  // Leaky integrator state for triangle wave
40	  let triState = 0;
41	
42	  const osc: PolyBLEPOsc = {
43	    get phase() {
44	      return phase;
45	    },
46	    set phase(p: number) {
47	      phase = p;
48	    },
49	    type,
50	
51	    next(frequency: number, sampleRate: number): number {
52	      const dt = frequency / sampleRate; // phase increment per sample
53	
54	      let out: number;
55	      switch (osc.type) {
56	        case "sine":
57	          out = Math.sin(2 * Math.PI * phase);
58	          break;
59	
60	        case "saw": {
61	          // Naive sawtooth: ramp from -1 to 1
62	          out = 2 * phase - 1;
63	          out -= polyblep(phase, dt);
64	          break;
65	        }
66	
67	        case "square": {
68	          // Naive square: +1 for first half, -1 for second
69	          out = phase < 0.5 ? 1 : -1;
70	          out += polyblep(phase, dt);
71	          out -= polyblep((phase + 0.5) % 1, dt);
72	          break;
73	        }
74	
75	        case "triangle": {
76	          // Integrated square wave -> triangle via leaky integrator
77	          let sq = phase < 0.5 ? 1 : -1;
78	          sq += polyblep(phase, dt);
79	          sq -= polyblep((phase + 0.5) % 1, dt);
80	          // Integrate with leak
81	          triState = dt * sq + (1 - dt) * triState;
82	          // Scale and clamp to [-1, 1]
83	          out = Math.max(-1, Math.min(1, triState * 4));
84	          break;
85	        }
86	
87	        default:
88	          out = 0;
89	      }
90	
91	      // Advance phase
92	      phase += dt;
93	      if (phase >= 1) phase -= 1;
94	
95	      return out;
96	    },
97	
98	    reset(): void {
99	      phase = 0;
100	      triState = 0;
101	    },
102	  };
103	
104	  return osc;
105	}
106

1	/**
2	 * ADSR envelope generator with exponential curves.
3	 * Runs per-sample in the AudioWorklet — zero allocations.
4	 *
5	 * MIT-H4-6: Minimum release time floor of 2ms.
6	 */
7	
8	export type ADSRStage = "idle" | "attack" | "decay" | "sustain" | "release";
9	
10	export type ADSRParams = {
11	  attack: number; // seconds (0..10)
12	  decay: number; // seconds (0..10)
13	  sustain: number; // level (0..1)
14	  release: number; // seconds (0..10)
15	};
16	
17	/** Minimum release time in seconds (MIT-H4-6) */
18	const MIN_RELEASE_S = 0.002;
19	
20	/**
21	 * Stateful ADSR envelope.
22	 * Call `process()` once per sample. Mutates internal state.
23	 */
24	export type ADSREnvelope = {
25	  stage: ADSRStage;
26	  level: number;
27	  /** Trigger note-on. If legato, continues from current level. */
28	  gate(legato: boolean): void;
29	  /** Trigger note-off. Begins release from current level. */
30	  release(): void;
31	  /** Advance one sample. Returns envelope level [0, 1]. */
32	  process(params: ADSRParams, sampleRate: number): number;
33	  /** Hard reset to idle. */
34	  reset(): void;
35	};
36	
37	export function createADSREnvelope(): ADSREnvelope {
38	  let stage: ADSRStage = "idle";
39	  let level = 0;
40	  // Exponential time constant: how many samples to reach ~63% of target
41	  function timeToCoeff(timeS: number, sampleRate: number): number {
42	    if (timeS <= 0) return 1;
43	    // Exponential approach coefficient per sample
44	    return 1 - Math.exp(-1 / (timeS * sampleRate));
45	  }
46	
47	  const env: ADSREnvelope = {
48	    get stage() {
49	      return stage;
50	    },
51	    get level() {
52	      return level;
53	    },
54	
55	    gate(legato: boolean): void {
56	      if (!legato) {
57	        level = 0;
58	      }
59	      stage = "attack";
60	    },
61	
62	    release(): void {
63	      if (stage === "idle") return;
64	      stage = "release";
65	    },
66	
67	    process(params: ADSRParams, sampleRate: number): number {
68	      switch (stage) {
69	        case "idle":
70	          level = 0;
71	          break;
72	
73	        case "attack": {
74	          const coeff = timeToCoeff(params.attack, sampleRate);
75	          // Approach 1.0 + overshoot target for natural curve
76	          level += coeff * (1.2 - level);
77	          if (level >= 1) {
78	            level = 1;
79	            stage = "decay";
80	          }
81	          break;
82	        }
83	
84	        case "decay": {
85	          const coeff = timeToCoeff(params.decay, sampleRate);
86	          level += coeff * (params.sustain - level);
87	          // Close enough to sustain level
88	          if (Math.abs(level - params.sustain) < 0.001) {
89	            level = params.sustain;
90	            stage = "sustain";
91	          }
92	          break;
93	        }
94	
95	        case "sustain":
96	          level = params.sustain;
97	          break;
98	
99	        case "release": {
100	          const releaseTime = Math.max(params.release, MIN_RELEASE_S);
101	          const coeff = timeToCoeff(releaseTime, sampleRate);
102	          level += coeff * (0 - level);
103	          if (level < 0.0001) {
104	            level = 0;
105	            stage = "idle";
106	          }
107	          break;
108	        }
109	      }
110	
111	      return level;
112	    },
113	
114	    reset(): void {
115	      stage = "idle";
116	      level = 0;
117	    },
118	  };
119	
120	  return env;
121	}
122

1	/**
2	 * Biquad filter coefficient computation.
3	 * Based on Robert Bristow-Johnson's Audio EQ Cookbook.
4	 * Supports LP, HP, BP filter types.
5	 *
6	 * Runs per-voice in the AudioWorklet — coefficients recomputed
7	 * only when cutoff/resonance change (not per-sample).
8	 */
9	
10	export type FilterType = "lowpass" | "highpass" | "bandpass";
11	
12	/** Biquad filter coefficients: y[n] = (b0*x[n] + b1*x[n-1] + b2*x[n-2] - a1*y[n-1] - a2*y[n-2]) / a0 */
13	export type BiquadCoeffs = {
14	  b0: number;
15	  b1: number;
16	  b2: number;
17	  a0: number;
18	  a1: number;
19	  a2: number;
20	};
21	
22	/**
23	 * Compute biquad filter coefficients for the given parameters.
24	 * @param type Filter type
25	 * @param cutoff Cutoff frequency in Hz
26	 * @param q Q factor (resonance), typically 0.5..20
27	 * @param sampleRate Sample rate in Hz
28	 */
29	export function computeBiquadCoeffs(
30	  type: FilterType,
31	  cutoff: number,
32	  q: number,
33	  sampleRate: number,
34	): BiquadCoeffs {
35	  // Clamp cutoff to Nyquist
36	  const nyquist = sampleRate / 2;
37	  const fc = Math.min(Math.max(cutoff, 20), nyquist - 100);
38	  const qClamped = Math.max(q, 0.1);
39	
40	  const w0 = (2 * Math.PI * fc) / sampleRate;
41	  const cosW0 = Math.cos(w0);
42	  const sinW0 = Math.sin(w0);
43	  const alpha = sinW0 / (2 * qClamped);
44	
45	  let b0: number, b1: number, b2: number, a0: number, a1: number, a2: number;
46	
47	  switch (type) {
48	    case "lowpass":
49	      b0 = (1 - cosW0) / 2;
50	      b1 = 1 - cosW0;
51	      b2 = (1 - cosW0) / 2;
52	      a0 = 1 + alpha;
53	      a1 = -2 * cosW0;
54	      a2 = 1 - alpha;
55	      break;
56	
57	    case "highpass":
58	      b0 = (1 + cosW0) / 2;
59	      b1 = -(1 + cosW0);
60	      b2 = (1 + cosW0) / 2;
61	      a0 = 1 + alpha;
62	      a1 = -2 * cosW0;
63	      a2 = 1 - alpha;
64	      break;
65	
66	    case "bandpass":
67	      b0 = alpha;
68	      b1 = 0;
69	      b2 = -alpha;
70	      a0 = 1 + alpha;
71	      a1 = -2 * cosW0;
72	      a2 = 1 - alpha;
73	      break;
74	  }
75	
76	  return { b0, b1, b2, a0, a1, a2 };
77	}
78	
79	/**
80	 * Stateful biquad filter for per-voice processing.
81	 * Maintains delay line state. Zero-allocation in process().
82	 */
83	export type BiquadFilter = {
84	  type: FilterType;
85	  /** Process a single sample through the filter. */
86	  process(input: number, coeffs: BiquadCoeffs): number;
87	  /** Reset delay line state. */
88	  reset(): void;
89	};
90	
91	export function createBiquadFilter(type: FilterType = "lowpass"): BiquadFilter {
92	  // Delay line: x[n-1], x[n-2], y[n-1], y[n-2]
93	  let x1 = 0;
94	  let x2 = 0;
95	  let y1 = 0;
96	  let y2 = 0;
97	
98	  return {
99	    type,
100	
101	    process(input: number, coeffs: BiquadCoeffs): number {
102	      const { b0, b1, b2, a0, a1, a2 } = coeffs;
103	      const output = (b0 * input + b1 * x1 + b2 * x2 - a1 * y1 - a2 * y2) / a0;
104	
105	      // Shift delay line
106	      x2 = x1;
107	      x1 = input;
108	      y2 = y1;
109	      y1 = output;
110	
111	      return output;
112	    },
113	
114	    reset(): void {
115	      x1 = x2 = y1 = y2 = 0;
116	    },
117	  };
118	}
