1	/**
2	 * LFO (Low Frequency Oscillator) for modulation.
3	 * Supports sine, square, triangle, and sample-and-hold shapes.
4	 * Output range: [-1, 1], scaled by depth at the modulation destination.
5	 */
6	
7	export type LFOShape = "sine" | "square" | "triangle" | "sample-and-hold";
8	
9	/**
10	 * Stateful LFO. Call `process()` once per sample.
11	 * Zero-allocation in the hot path.
12	 */
13	export type LFO = {
14	  shape: LFOShape;
15	  /** Advance one sample. Returns output in [-1, 1]. */
16	  process(rate: number, sampleRate: number): number;
17	  /** Reset phase. */
18	  reset(): void;
19	};
20	
21	export function createLFO(shape: LFOShape = "sine"): LFO {
22	  let phase = 0;
23	  let shValue = 0; // Sample-and-hold current value
24	  let prevPhase = 0; // For detecting S&H trigger
25	
26	  const lfo: LFO = {
27	    shape,
28	
29	    process(rate: number, sampleRate: number): number {
30	      const dt = rate / sampleRate;
31	      let out: number;
32	
33	      switch (lfo.shape) {
34	        case "sine":
35	          out = Math.sin(2 * Math.PI * phase);
36	          break;
37	
38	        case "square":
39	          out = phase < 0.5 ? 1 : -1;
40	          break;
41	
42	        case "triangle":
43	          // Ramp 0->1->0 mapped to -1->1->-1
44	          out = phase < 0.5 ? 4 * phase - 1 : 3 - 4 * phase;
45	          break;
46	
47	        case "sample-and-hold":
48	          // New random value each cycle
49	          if (phase < prevPhase) {
50	            shValue = Math.random() * 2 - 1;
51	          }
52	          out = shValue;
53	          break;
54	
55	        default:
56	          out = 0;
57	      }
58	
59	      prevPhase = phase;
60	      phase += dt;
61	      if (phase >= 1) phase -= 1;
62	
63	      return out;
64	    },
65	
66	    reset(): void {
67	      phase = 0;
68	      prevPhase = 0;
69	      shValue = 0;
70	    },
71	  };
72	
73	  return lfo;
74	}
