1	/**
2	 * Synthesizer AudioWorklet processor.
3	 * Runs on the audio rendering thread — zero allocations in process().
4	 *
5	 * Architecture: 16 fixed voices, each with:
6	 * - 2 PolyBLEP oscillators
7	 * - Biquad filter (LP/HP/BP)
8	 * - ADSR amplitude envelope
9	 * - ADSR filter envelope
10	 * Shared: 2 LFOs, hardwired modulation matrix.
11	 *
12	 * INV-3/NFR-14: Zero-allocation process().
13	 * MIT-H4-5: Oldest-steal with 5ms crossfade.
14	 * MIT-H4-6: 2ms minimum release time.
15	 * R-STA-05: Legato mode with pitch glide.
16	 */
17	
18	import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
19	import {
20	  createADSREnvelope,
21	  type ADSREnvelope,
22	  type ADSRParams,
23	} from "./dsp/adsr";
24	import {
25	  computeBiquadCoeffs,
26	  createBiquadFilter,
27	  type BiquadFilter,
28	  type BiquadCoeffs,
29	} from "./dsp/biquad-coeffs";
30	import { createLFO, type LFO } from "./dsp/lfo";
31	import {
32	  createVoiceAllocator,
33	  type VoiceAllocator,
34	  MAX_VOICES,
35	} from "./dsp/voice-allocator";
36	import {
37	  midiToFreq,
38	  WAVEFORM_TYPES,
39	  FILTER_TYPES,
40	  LFO_SHAPES,
41	  type SynthVoiceCommand,
42	  type SynthParameterMap,
43	  DEFAULT_SYNTH_PARAMS,
44	} from "./synth-types";
45	
46	// ─── AudioWorklet globals (not in TypeScript's lib by default) ───
47	declare const sampleRate: number;
48	declare class AudioWorkletProcessor {
49	  readonly port: MessagePort;
50	  constructor();
51	  process(
52	    inputs: Float32Array[][],
53	    outputs: Float32Array[][],
54	    parameters: Record<string, Float32Array>,
55	  ): boolean;
56	}
57	declare function registerProcessor(
58	  name: string,
59	  ctor: typeof AudioWorkletProcessor,
60	): void;
61	
62	// ─── Per-Voice State (pre-allocated) ───
63	
64	type VoiceData = {
65	  osc1: PolyBLEPOsc;
66	  osc2: PolyBLEPOsc;
67	  ampEnv: ADSREnvelope;
68	  filterEnv: ADSREnvelope;
69	  filter: BiquadFilter;
70	  targetFreq: number;
71	  currentFreq: number;
72	  velocity: number;
73	};
74	
75	function createVoiceData(): VoiceData {
76	  return {
77	    osc1: createPolyBLEPOsc("saw"),
78	    osc2: createPolyBLEPOsc("saw"),
79	    ampEnv: createADSREnvelope(),
80	    filterEnv: createADSREnvelope(),
81	    filter: createBiquadFilter("lowpass"),
82	    targetFreq: 440,
83	    currentFreq: 440,
84	    velocity: 0,
85	  };
86	}
87	
88	/** Safe access to pre-allocated arrays */
89	function at<T>(arr: T[], i: number): T {
90	  const val = arr[i];
91	  if (val === undefined) throw new Error("Index out of bounds");
92	  return val;
93	}
94	
95	class SynthProcessor extends AudioWorkletProcessor {
96	  private allocator: VoiceAllocator;
97	  private voiceData: VoiceData[];
98	  private lfo1: LFO;
99	  private lfo2: LFO;
100	  private params: SynthParameterMap;
101	  private coeffs: BiquadCoeffs;
102	  private alive = true;
103	
104	  constructor() {
105	    super();
106	
107	    this.allocator = createVoiceAllocator();
108	    this.voiceData = Array.from({ length: MAX_VOICES }, () =>
109	      createVoiceData(),
110	    );
111	    this.lfo1 = createLFO("sine");
112	    this.lfo2 = createLFO("sine");
113	    this.params = { ...DEFAULT_SYNTH_PARAMS };
114	    this.coeffs = { b0: 0, b1: 0, b2: 0, a0: 1, a1: 0, a2: 0 };
115	
116	    this.port.onmessage = (e: MessageEvent) => {
117	      this.handleMessage(e.data as SynthVoiceCommand);
118	    };
119	  }
120	
121	  private handleMessage(cmd: SynthVoiceCommand): void {
122	    switch (cmd.type) {
123	      case "noteOn": {
124	        const legato = cmd.legato;
125	        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
126	        const vd = at(this.voiceData, idx);
127	
128	        const baseFreq = midiToFreq(cmd.note);
129	        vd.targetFreq = baseFreq;
130	        vd.velocity = cmd.velocity / 127;
131	
132	        if (!legato || vd.currentFreq === 0) {
133	          vd.currentFreq = baseFreq;
134	        }
135	
136	        if (!legato) {
137	          vd.osc1.reset();
138	          vd.osc2.reset();
139	          vd.filter.reset();
140	        }
141	
142	        vd.osc1.type = this.params.osc1Type;
143	        vd.osc2.type = this.params.osc2Type;
144	        vd.filter.type = this.params.filterType;
145	
146	        vd.ampEnv.gate(legato);
147	        vd.filterEnv.gate(legato);
148	        break;
149	      }
150	
151	      case "noteOff": {
152	        const idx = this.allocator.noteOff(cmd.note);
153	        if (idx >= 0) {
154	          const vd = at(this.voiceData, idx);
155	          vd.ampEnv.release();
156	          vd.filterEnv.release();
157	        }
158	        break;
159	      }
160	
161	      case "allNotesOff":
162	        for (let i = 0; i < MAX_VOICES; i++) {
163	          at(this.voiceData, i).ampEnv.release();
164	          at(this.voiceData, i).filterEnv.release();
165	        }
166	        break;
167	
168	      case "setParam":
169	        this.setParamValue(cmd.key, cmd.value);
170	        break;
171	    }
172	  }
173	
174	  private setParamValue(key: string, value: number): void {
175	    switch (key) {
176	      case "osc1Type":
177	        this.params.osc1Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
178	        break;
179	      case "osc2Type":
180	        this.params.osc2Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
181	        break;
182	      case "filterType": {
183	        const ft = FILTER_TYPES[Math.round(value)] ?? "lowpass";
184	        this.params.filterType = ft;
185	        for (let i = 0; i < MAX_VOICES; i++) {
186	          at(this.voiceData, i).filter.type = ft;
187	        }
188	        break;
189	      }
190	      case "lfo1Shape":
191	        this.params.lfo1Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
192	        this.lfo1.shape = this.params.lfo1Shape;
193	        break;
194	      case "lfo2Shape":
195	        this.params.lfo2Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
196	        this.lfo2.shape = this.params.lfo2Shape;
197	        break;
198	      default:
199	        (this.params as Record<string, unknown>)[key] = value;
200	        break;
201	    }
202	  }
203	
204	  process(
205	    _inputs: Float32Array[][],
206	    outputs: Float32Array[][],
207	    _parameters: Record<string, Float32Array>,
208	  ): boolean {
209	    const output = outputs[0];
210	    if (!output) return this.alive;
211	
212	    const outL = output[0];
213	    const outR = output[1] ?? output[0];
214	    if (!outL || !outR) return this.alive;
215	
216	    const numSamples = outL.length;
217	    const sr = sampleRate;
218	    const p = this.params;
219	
220	    const ampParams: ADSRParams = {
221	      attack: p.ampAttack,
222	      decay: p.ampDecay,
223	      sustain: p.ampSustain,
224	      release: p.ampRelease,
225	    };
226	
227	    const filterParams: ADSRParams = {
228	      attack: p.filterAttack,
229	      decay: p.filterDecay,
230	      sustain: p.filterSustain,
231	      release: p.filterRelease,
232	    };
233	
234	    for (let s = 0; s < numSamples; s++) {
235	      const lfo1Val = this.lfo1.process(p.lfo1Rate, sr);
236	      const lfo2Val = this.lfo2.process(p.lfo2Rate, sr);
237	
238	      let mixL = 0;
239	      let mixR = 0;
240	
241	      for (let vi = 0; vi < MAX_VOICES; vi++) {
242	        const voice = at(this.allocator.voices as unknown[], vi) as {
243	          state: string;
244	        };
245	        if (voice.state === "idle") continue;
246	
247	        const vd = at(this.voiceData, vi);
248	
249	        // Pitch glide (R-STA-05)
250	        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
251	          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
252	          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
253	        } else {
254	          vd.currentFreq = vd.targetFreq;
255	        }
256	
257	        const baseFreq = vd.currentFreq;
258	
259	        // LFO1 -> pitch modulation (in semitones)
260	        const pitchMod = lfo1Val * p.lfo1Depth * 2;
261	        const pitchMultiplier = Math.pow(2, pitchMod / 12);
262	
263	        const freq1 =
264	          baseFreq *
265	          Math.pow(2, p.osc1Octave) *
266	          Math.pow(2, p.osc1Detune / 1200) *
267	          pitchMultiplier;
268	        const freq2 =
269	          baseFreq *
270	          Math.pow(2, p.osc2Octave) *
271	          Math.pow(2, p.osc2Detune / 1200) *
272	          pitchMultiplier;
273	
274	        const osc1Out = vd.osc1.next(freq1, sr) * p.osc1Level;
275	        const osc2Out = vd.osc2.next(freq2, sr) * p.osc2Level;
276	        let sample = osc1Out + osc2Out;
277	
278	        // Filter envelope -> cutoff modulation
279	        const filterEnvVal = vd.filterEnv.process(filterParams, sr);
280	        const envCutoffMod = filterEnvVal * p.filterEnvDepth;
281	
282	        // LFO1 -> cutoff modulation
283	        const lfoCutoffMod = lfo1Val * p.lfo1Depth * 12;
284	
285	        // Velocity -> filter modulation
286	        const velCutoffMod = vd.velocity * 24;
287	
288	        const totalCutoffMod = envCutoffMod + lfoCutoffMod + velCutoffMod;
289	        const modulatedCutoff =
290	          p.filterCutoff * Math.pow(2, totalCutoffMod / 12);
291	        const clampedCutoff = Math.min(
292	          Math.max(modulatedCutoff, 20),
293	          sr / 2 - 100,
294	        );
295	
296	        const c = computeBiquadCoeffs(
297	          p.filterType,
298	          clampedCutoff,
299	          p.filterResonance,
300	          sr,
301	        );
302	        this.coeffs.b0 = c.b0;
303	        this.coeffs.b1 = c.b1;
304	        this.coeffs.b2 = c.b2;
305	        this.coeffs.a0 = c.a0;
306	        this.coeffs.a1 = c.a1;
307	        this.coeffs.a2 = c.a2;
308	
309	        sample = vd.filter.process(sample, this.coeffs);
310	
311	        // Amplitude envelope
312	        const ampLevel = vd.ampEnv.process(ampParams, sr);
313	
314	        // LFO2 -> amplitude modulation (tremolo)
315	        const ampMod = 1 + lfo2Val * p.lfo2Depth * 0.5;
316	
317	        // Velocity -> amplitude
318	        const velAmp = 0.5 + vd.velocity * 0.5;
319	
320	        sample *= ampLevel * ampMod * velAmp * p.masterGain;
321	
322	        // Mark idle when envelope finishes
323	        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
324	          this.allocator.markIdle(vi);
325	          continue;
326	        }
327	
328	        mixL += sample;
329	        mixR += sample;
330	      }
331	
332	      this.allocator.processStealFade(sr);
333	
334	      outL[s] = mixL;
335	      outR[s] = mixR;
336	    }
337	
338	    return this.alive;
339	  }
340	}
341	
342	registerProcessor("synth-processor", SynthProcessor);
