2	 * SynthInstrument: main-thread controller for the synth AudioWorklet.
3	 * Creates AudioWorkletNode, sends voice commands, manages parameters,
4	 * connects output to mixer channel strip.
5	 *
6	 * R-EVT-08: Real-time parameter changes via MessagePort.
7	 */
8	
9	import type { SynthVoiceCommand, SynthParameterMap } from "./synth-types";
10	import { DEFAULT_SYNTH_PARAMS } from "./synth-types";
11	import type { MixerEngine } from "@audio/mixer/types";
12	
13	export type SynthInstrument = {
14	  /** The audio output node — connect to mixer channel strip. */
15	  readonly output: AudioNode;
16	  /** Current parameter values. */
17	  readonly params: Readonly<SynthParameterMap>;
18	  /** Send a note-on to the synth. */
19	  noteOn(note: number, velocity: number, legato?: boolean): void;
20	  /** Send a note-off to the synth. */
21	  noteOff(note: number): void;
22	  /** Release all notes. */
23	  allNotesOff(): void;
24	  /** Set a synth parameter (forwarded to worklet). */
25	  setParam<K extends keyof SynthParameterMap>(
26	    key: K,
27	    value: SynthParameterMap[K],
28	  ): void;
29	  /** Connect to a mixer channel. */
30	  connectToMixer(mixer: MixerEngine, trackId: string): void;
31	  /** Disconnect from mixer. */
32	  disconnectFromMixer(mixer: MixerEngine, trackId: string): void;
33	  /** Clean up all resources. */
34	  dispose(): void;
35	};
36	
37	/** URL for the worklet processor module */
38	const PROCESSOR_URL = new URL("./synth-processor.ts", import.meta.url);
39	
40	/**
41	 * Create a SynthInstrument connected to the given AudioContext.
42	 * Must call `audioCtx.audioWorklet.addModule()` first via loadWorkletModule().
43	 */
44	export async function createSynthInstrument(
45	  ctx: AudioContext,
46	): Promise<SynthInstrument> {
47	  // Load the worklet module
48	  await ctx.audioWorklet.addModule(PROCESSOR_URL.href);
49	
50	  const node = new AudioWorkletNode(ctx, "synth-processor", {
51	    numberOfInputs: 0,
52	    numberOfOutputs: 1,
53	    outputChannelCount: [2],
54	  });
55	
56	  const params: SynthParameterMap = { ...DEFAULT_SYNTH_PARAMS };
57	
58	  function postCommand(cmd: SynthVoiceCommand): void {
59	    node.port.postMessage(cmd);
60	  }
61	
62	  const instrument: SynthInstrument = {
63	    output: node,
64	    params,
65	
66	    noteOn(note: number, velocity: number, legato = false): void {
67	      postCommand({ type: "noteOn", note, velocity, legato });
68	    },
69	
70	    noteOff(note: number): void {
71	      postCommand({ type: "noteOff", note });
72	    },
73	
74	    allNotesOff(): void {
75	      postCommand({ type: "allNotesOff" });
76	    },
77	
78	    setParam<K extends keyof SynthParameterMap>(
79	      key: K,
80	      value: SynthParameterMap[K],
81	    ): void {
82	      (params as Record<string, unknown>)[key] = value;
83	
84	      // Map enum types to numeric index for the worklet
85	      let numericValue: number;
86	      if (typeof value === "string") {
87	        // Lookup string in appropriate type array
88	        switch (key) {
89	          case "osc1Type":
90	          case "osc2Type":
91	            numericValue = ["sine", "saw", "square", "triangle"].indexOf(value);
92	            break;
93	          case "filterType":
94	            numericValue = ["lowpass", "highpass", "bandpass"].indexOf(value);
95	            break;
96	          case "lfo1Shape":
97	          case "lfo2Shape":
98	            numericValue = [
99	              "sine",
100	              "square",
101	              "triangle",
102	              "sample-and-hold",
103	            ].indexOf(value);
104	            break;
105	          default:
106	            numericValue = 0;
107	        }
108	      } else {
109	        numericValue = value;
110	      }
111	
112	      postCommand({
113	        type: "setParam",
114	        key: key as string,
115	        value: numericValue,
116	      });
117	    },
118	
119	    connectToMixer(mixer: MixerEngine, trackId: string): void {
120	      const strip = mixer.getOrCreateStrip(trackId);
121	      node.connect(strip.inputGain);
122	    },
123	
124	    disconnectFromMixer(_mixer: MixerEngine, _trackId: string): void {
125	      node.disconnect();
126	    },
127	
128	    dispose(): void {
129	      node.disconnect();
130	      node.port.close();
131	    },
132	  };
133	
134	  return instrument;
135	}
