1	/**
2	 * Zustand store for synthesizer state.
3	 * Per-instrument-track synth parameter state, serializable.
4	 */
5	
6	import { create } from "zustand";
7	import {
8	  DEFAULT_SYNTH_PARAMS,
9	  type SynthParameterMap,
10	} from "@audio/synth/synth-types";
11	
12	export type SynthTrackState = {
13	  readonly trackId: string;
14	  readonly params: SynthParameterMap;
15	  readonly legato: boolean;
16	};
17	
18	export type SynthStore = {
19	  /** Per-track synth state keyed by track ID */
20	  synths: Record<string, SynthTrackState>;
21	
22	  /** Initialize synth state for a track */
23	  initSynth: (trackId: string) => void;
24	  /** Remove synth state for a track */
25	  removeSynth: (trackId: string) => void;
26	  /** Set a synth parameter for a track */
27	  setParam: <K extends keyof SynthParameterMap>(
28	    trackId: string,
29	    key: K,
30	    value: SynthParameterMap[K],
31	  ) => void;
32	  /** Toggle legato mode */
33	  setLegato: (trackId: string, legato: boolean) => void;
34	  /** Get synth params for a track (returns defaults if not initialized) */
35	  getParams: (trackId: string) => SynthParameterMap;
36	};
37	
38	export const useSynthStore = create<SynthStore>()((set, get) => ({
39	  synths: {},
40	
41	  initSynth(trackId) {
42	    set((s) => {
43	      if (s.synths[trackId]) return s;
44	      return {
45	        synths: {
46	          ...s.synths,
47	          [trackId]: {
48	            trackId,
49	            params: { ...DEFAULT_SYNTH_PARAMS },
50	            legato: false,
51	          },
52	        },
53	      };
54	    });
55	  },
56	
57	  removeSynth(trackId) {
58	    set((s) => {
59	      if (!s.synths[trackId]) return s;
60	      return {
61	        synths: Object.fromEntries(
62	          Object.entries(s.synths).filter(([k]) => k !== trackId),
63	        ),
64	      };
65	    });
66	  },
67	
68	  setParam(trackId, key, value) {
69	    set((s) => {
70	      const synth = s.synths[trackId];
71	      if (!synth) return s;
72	      return {
73	        synths: {
74	          ...s.synths,
75	          [trackId]: {
76	            ...synth,
77	            params: { ...synth.params, [key]: value },
78	          },
79	        },
80	      };
81	    });
82	  },
83	
84	  setLegato(trackId, legato) {
85	    set((s) => {
86	      const synth = s.synths[trackId];
87	      if (!synth) return s;
88	      return {
89	        synths: {
90	          ...s.synths,
91	          [trackId]: { ...synth, legato },
92	        },
93	      };
94	    });
95	  },
96	
97	  getParams(trackId) {
98	    const synth = get().synths[trackId];
99	    return synth?.params ?? { ...DEFAULT_SYNTH_PARAMS };
100	  },
101	}));
