35	export function VirtualKeyboard({
36	  onNoteOn,
37	  onNoteOff,
38	}: VirtualKeyboardProps): React.JSX.Element {
39	  const activeNotes = useRef(new Set<number>());
40	
41	  const handleMouseDown = useCallback(
42	    (note: number) => {
43	      if (!activeNotes.current.has(note)) {
44	        activeNotes.current.add(note);
45	        onNoteOn(note, 100);
46	      }
47	    },
48	    [onNoteOn],
49	  );
50	
51	  const handleMouseUp = useCallback(
52	    (note: number) => {
53	      if (activeNotes.current.has(note)) {
54	        activeNotes.current.delete(note);
55	        onNoteOff(note);
56	      }
57	    },
58	    [onNoteOff],
59	  );
60	
61	  const handleMouseLeave = useCallback(
62	    (note: number) => {
63	      if (activeNotes.current.has(note)) {
64	        activeNotes.current.delete(note);
65	        onNoteOff(note);
66	      }
67	    },
68	    [onNoteOff],
69	  );
70	
71	  const whiteKeys: React.JSX.Element[] = [];
72	  const blackKeys: React.JSX.Element[] = [];
73	
74	  let whiteIndex = 0;
75	
76	  for (let octave = 0; octave < NUM_OCTAVES; octave++) {
77	    for (const offset of WHITE_KEY_OFFSETS) {
78	      const note = OCTAVE_START + octave * 12 + offset;
79	      const x = whiteIndex * WHITE_KEY_WIDTH;
80	      whiteKeys.push(
