124	          }}
125	          onMouseUp={() => {
126	            handleMouseUp(note);
127	          }}
128	          onMouseLeave={() => {
129	            handleMouseLeave(note);
130	          }}
131	          style={{
132	            position: "absolute",
133	            left: x,
134	            top: 0,
135	            width: BLACK_KEY_WIDTH,
136	            height: BLACK_KEY_HEIGHT,
137	            backgroundColor: tokens.color.black,
138	            border: BLACK_KEY_BORDER,
139	            cursor: "pointer",
140	            userSelect: "none",
141	            zIndex: 2,
142	          }}
143	        />,
144	      );
145	    }
146	  }
147	
148	  const totalWidth = whiteIndex * WHITE_KEY_WIDTH;
149	
150	  return (
151	    <div
152	      data-testid="virtual-keyboard"
153	      style={{
154	        position: "relative",
155	        width: totalWidth,
156	        height: WHITE_KEY_HEIGHT,
157	        flexShrink: 0,
158	      }}
159	    >
160	      {whiteKeys}
161	      {blackKeys}
162	    </div>
163	  );
164	}
