  1	/**
  2	 * Voice allocator: 16-voice fixed pool with oldest-steal + 5ms crossfade.
  3	 * INV-5: Fixed pool size, never grows.
  4	 * MIT-H4-5: Oldest-steal with 5ms crossfade on stolen voices.
  5	 * R-STA-05: Legato mode with pitch glide.
  6	 *
  7	 * Zero-allocation in allocate/release — no objects created at runtime.
  8	 */
  9	
 10	/** Maximum number of concurrent voices */
 11	export const MAX_VOICES = 16;
 12	
 13	/** Crossfade time in seconds when stealing a voice (MIT-H4-5) */
 14	export const STEAL_CROSSFADE_S = 0.005;
 15	
 16	export type VoiceState = "idle" | "active" | "releasing" | "stealing";
 17	
 18	export type Voice = {
 19	  state: VoiceState;
 20	  note: number; // MIDI note number
 21	  velocity: number; // 0..127
 22	  /** Monotonically increasing counter set on each note-on for oldest-steal */
 23	  age: number;
 24	  /** Samples remaining in steal crossfade */
 25	  stealFadeSamples: number;
 26	  /** Crossfade gain multiplier for the old voice being stolen */
 27	  stealFadeGain: number;
 28	};
 29	
 30	export type VoiceAllocator = {
 31	  readonly voices: readonly Voice[];
 32	  /** Allocate a voice for a note-on. Returns voice index. */
 33	  noteOn(note: number, velocity: number, legato: boolean): number;
 34	  /** Release a voice for a note-off. Returns voice index or -1 if not found. */
 35	  noteOff(note: number): number;
 36	  /** Advance steal crossfade for one sample. Call once per render sample. */
 37	  processStealFade(sampleRate: number): void;
 38	  /** Mark a voice as idle (called when envelope finishes release). */
 39	  markIdle(index: number): void;
 40	  /** Reset all voices to idle. */
 41	  reset(): void;
 42	};
 43	
 44	/** Safe array access that throws on out-of-bounds (pool is fixed-size). */
 45	function v(voices: Voice[], i: number): Voice {
 46	  const voice = voices[i];
 47	  if (!voice) throw new Error("Voice index out of bounds");
 48	  return voice;
 49	}
 50	
 51	export function createVoiceAllocator(): VoiceAllocator {
 52	  let ageCounter = 0;
 53	
 54	  // Pre-allocate voice pool (INV-5: fixed size)
 55	  const voices: Voice[] = Array.from({ length: MAX_VOICES }, () => ({
 56	    state: "idle" as VoiceState,
 57	    note: -1,
 58	    velocity: 0,
 59	    age: 0,
 60	    stealFadeSamples: 0,
 61	    stealFadeGain: 0,
 62	  }));
 63	
 64	  function findIdleVoice(): number {
 65	    for (let i = 0; i < MAX_VOICES; i++) {
 66	      if (v(voices, i).state === "idle") return i;
 67	    }
 68	    return -1;
 69	  }
 70	
 71	  function findOldestActive(): number {
 72	    let oldestIdx = -1;
 73	    let oldestAge = Infinity;
 74	
 75	    for (let i = 0; i < MAX_VOICES; i++) {
 76	      const voice = v(voices, i);
 77	      if (voice.state === "releasing" && voice.age < oldestAge) {
 78	        oldestAge = voice.age;
 79	        oldestIdx = i;
 80	      }
 81	    }
 82	
 83	    if (oldestIdx === -1) {
 84	      for (let i = 0; i < MAX_VOICES; i++) {
 85	        const voice = v(voices, i);
 86	        if (
 87	          (voice.state === "active" || voice.state === "stealing") &&
 88	          voice.age < oldestAge
 89	        ) {
 90	          oldestAge = voice.age;
 91	          oldestIdx = i;
 92	        }
 93	      }
 94	    }
 95	
 96	    return oldestIdx;
 97	  }
 98	
 99	  function findVoiceForNote(note: number): number {
100	    for (let i = 0; i < MAX_VOICES; i++) {
101	      const voice = v(voices, i);
102	      if (
103	        voice.note === note &&
104	        (voice.state === "active" || voice.state === "releasing")
105	      ) {
106	        return i;
107	      }
108	    }
109	    return -1;
110	  }
111	
112	  const allocator: VoiceAllocator = {
113	    voices,
114	
115	    noteOn(note: number, velocity: number, legato: boolean): number {
116	      ageCounter++;
117	
118	      if (legato) {
119	        const existing = findVoiceForNote(note);
120	        if (existing !== -1) {
121	          const voice = v(voices, existing);
122	          voice.note = note;
123	          voice.velocity = velocity;
124	          voice.age = ageCounter;
125	          voice.state = "active";
126	          return existing;
127	        }
128	        for (let i = 0; i < MAX_VOICES; i++) {
129	          const voice = v(voices, i);
130	          if (voice.state === "active") {
131	            voice.note = note;
132	            voice.velocity = velocity;
133	            voice.age = ageCounter;
134	            return i;
135	          }
136	        }
137	      }
138	
139	      let idx = findIdleVoice();
140	
141	      if (idx === -1) {
142	        idx = findOldestActive();
143	        if (idx !== -1) {
144	          const voice = v(voices, idx);
145	          voice.state = "stealing";
146	          voice.stealFadeSamples = 0;
147	          voice.stealFadeGain = 1;
148	        }
149	      }
150	
151	      if (idx === -1) {
152	        idx = 0;
153	      }
154	
155	      const voice = v(voices, idx);
156	      voice.note = note;
157	      voice.velocity = velocity;
158	      voice.age = ageCounter;
159	      voice.state = "active";
160	      voice.stealFadeSamples = 0;
161	      voice.stealFadeGain = 0;
162	
163	      return idx;
164	    },
165	
166	    noteOff(note: number): number {
167	      const idx = findVoiceForNote(note);
168	      if (idx === -1) return -1;
169	
170	      v(voices, idx).state = "releasing";
171	      return idx;
172	    },
173	
174	    processStealFade(sampleRate: number): void {
175	      const crossfadeSamples = Math.floor(STEAL_CROSSFADE_S * sampleRate);
176	
177	      for (let i = 0; i < MAX_VOICES; i++) {
178	        const voice = v(voices, i);
179	        if (voice.state === "stealing") {
180	          voice.stealFadeSamples++;
181	          voice.stealFadeGain = Math.max(
182	            0,
183	            1 - voice.stealFadeSamples / crossfadeSamples,
184	          );
185	          if (voice.stealFadeSamples >= crossfadeSamples) {
186	            voice.state = "active";
187	            voice.stealFadeGain = 0;
188	            voice.stealFadeSamples = 0;
189	          }
190	        }
191	      }
192	    },
193	
194	    markIdle(index: number): void {
195	      if (index >= 0 && index < MAX_VOICES) {
196	        const voice = v(voices, index);
197	        voice.state = "idle";
198	        voice.note = -1;
199	        voice.velocity = 0;
200	        voice.stealFadeSamples = 0;
201	        voice.stealFadeGain = 0;
202	      }
203	    },
204	
205	    reset(): void {
206	      ageCounter = 0;
207	      for (let i = 0; i < MAX_VOICES; i++) {
208	        const voice = v(voices, i);
209	        voice.state = "idle";
210	        voice.note = -1;
211	        voice.velocity = 0;
212	        voice.age = 0;
213	        voice.stealFadeSamples = 0;
214	        voice.stealFadeGain = 0;
215	      }
216	    },
217	  };
218	
219	  return allocator;
220	}

