  b0: number;
  b1: number;
  b2: number;
  a0: number;
  a1: number;
  a2: number;
};

/**
 * Compute biquad filter coefficients for the given parameters.
 * @param type Filter type
 * @param cutoff Cutoff frequency in Hz
 * @param q Q factor (resonance), typically 0.5..20
 * @param sampleRate Sample rate in Hz
